import React, { useState, useEffect, useRef } from 'react';
import { Modal } from './Modal';
import { CalendarEvent, Region, RecurrenceType } from '../types';
import { toDateString, toTimeString } from '../utils/dateUtils';
import { Clock, MapPin, AlignLeft, Type, Calendar as CalendarIcon, Globe, ChevronDown, Repeat, Check } from 'lucide-react';
import { MiniCalendar } from './MiniCalendar';

interface EventModalProps {
  isOpen: boolean;
  onClose: () => void;
  onSave: (event: CalendarEvent) => void;
  onDelete: (id: string) => void;
  initialDate?: Date | null;
  existingEvent?: CalendarEvent | null;
}

interface DateInputProps {
    dateStr: string; // ISO YYYY-MM-DD
    onChange: (iso: string) => void;
    onFocus: () => void;
    inputRef?: React.RefObject<HTMLInputElement | null>; 
    onComplete?: () => void; 
}

const DateInput: React.FC<DateInputProps> = ({ dateStr, onChange, onFocus, inputRef, onComplete }) => {
    const [d, setD] = useState('');
    const [m, setM] = useState('');
    const [y, setY] = useState('');

    const monthRef = useRef<HTMLInputElement>(null);
    const yearRef = useRef<HTMLInputElement>(null);
    const isFocused = useRef(false);

    useEffect(() => {
        if (isFocused.current) return;
        if (dateStr) {
            const [year, month, day] = dateStr.split('-');
            setY(year);
            setM(month);
            setD(day);
        } else {
            setD(''); setM(''); setY('');
        }
    }, [dateStr]);

    const updateDate = (day: string, month: string, year: string) => {
        if (day.length >= 1 && month.length >= 1 && year.length === 4) {
             const newDate = new Date(parseInt(year), parseInt(month) - 1, parseInt(day));
             if (newDate.getDate() === parseInt(day) && newDate.getMonth() === parseInt(month) - 1) {
                 onChange(toDateString(newDate));
             }
        }
    };

    const handleDayChange = (e: React.ChangeEvent<HTMLInputElement>) => {
        let val = e.target.value;
        if (!/^\d*$/.test(val)) return;
        setD(val);
        updateDate(val, m, y);
        if (val.length === 2) monthRef.current?.focus();
    };

    const handleMonthChange = (e: React.ChangeEvent<HTMLInputElement>) => {
        let val = e.target.value;
        if (!/^\d*$/.test(val)) return;
        setM(val);
        updateDate(d, val, y);
        if (val.length === 2) yearRef.current?.focus();
    };

    const handleYearChange = (e: React.ChangeEvent<HTMLInputElement>) => {
        let val = e.target.value;
        if (!/^\d*$/.test(val)) return;
        setY(val);
        updateDate(d, m, val);
        if (val.length === 4 && onComplete) {
            onComplete();
        }
    };

    const handleDayBlur = () => {
        isFocused.current = false;
        if (d === '' && dateStr) {
             const [_, __, day] = dateStr.split('-');
             setD(day);
        }
    };

    const handleMonthBlur = () => {
        isFocused.current = false;
        if (m === '' && dateStr) {
             const [_, month, __] = dateStr.split('-');
             setM(month);
        }
    };

    const handleFocus = (e: React.FocusEvent<HTMLInputElement>) => {
        isFocused.current = true;
        e.target.select();
        onFocus();
    };

    return (
        <div className="flex items-center gap-0.5 w-full h-full">
            <input
                ref={inputRef}
                type="text"
                placeholder="DD"
                value={d}
                maxLength={2}
                onChange={handleDayChange}
                onBlur={handleDayBlur}
                onFocus={handleFocus}
                className="bg-transparent outline-none text-gray-700 font-medium text-center w-8 rounded focus:bg-blue-200 transition-colors p-0 placeholder-gray-400"
            />
            <span className="text-gray-400 select-none">/</span>
            <input
                ref={monthRef}
                type="text"
                placeholder="MM"
                value={m}
                maxLength={2}
                onChange={handleMonthChange}
                onBlur={handleMonthBlur}
                onFocus={handleFocus}
                className="bg-transparent outline-none text-gray-700 font-medium text-center w-8 rounded focus:bg-blue-200 transition-colors p-0 placeholder-gray-400"
            />
            <span className="text-gray-400 select-none">/</span>
            <input
                ref={yearRef}
                type="text"
                placeholder="YYYY"
                maxLength={4}
                value={y}
                onChange={handleYearChange}
                onFocus={handleFocus}
                className="bg-transparent outline-none text-gray-700 font-medium text-center w-12 rounded focus:bg-blue-200 transition-colors p-0 placeholder-gray-400"
            />
        </div>
    );
};

const TimeSelect: React.FC<{ 
    value: string; 
    onChange: (val: string) => void; 
    inputRef?: React.RefObject<HTMLInputElement | null>;
    onComplete?: () => void;
}> = ({ value, onChange, inputRef, onComplete }) => {
    const [h = '00', m = '00'] = (value || '00:00').split(':');
    const minuteRef = useRef<HTMLInputElement>(null);
    const isFocused = useRef(false);

    const [localH, setLocalH] = useState(h.padStart(2, '0'));
    const [localM, setLocalM] = useState(m.padStart(2, '0'));

    useEffect(() => {
        if (isFocused.current) return;
        const [newH = '00', newM = '00'] = (value || '00:00').split(':');
        setLocalH(newH.padStart(2, '0'));
        setLocalM(newM.padStart(2, '0'));
    }, [value]);

    const updateTime = (newH: string, newM: string) => {
        onChange(`${newH}:${newM}`);
    };

    const handleHourChange = (e: React.ChangeEvent<HTMLInputElement>) => {
        let val = e.target.value;
        if (!/^\d*$/.test(val)) return;
        setLocalH(val);
        updateTime(val, localM);
        if (val.length === 2) minuteRef.current?.focus();
    };

    const handleHourBlur = () => {
        isFocused.current = false;
        let val = parseInt(localH, 10);
        if (isNaN(val)) val = 0;
        val = Math.min(23, Math.max(0, val));
        const formatted = val.toString().padStart(2, '0');
        setLocalH(formatted);
        updateTime(formatted, localM);
    };

    const handleMinuteChange = (e: React.ChangeEvent<HTMLInputElement>) => {
        let val = e.target.value;
        if (!/^\d*$/.test(val)) return;
        setLocalM(val);
        updateTime(localH, val);
        if (val.length === 2 && onComplete) {
            onComplete();
        }
    };

    const handleMinuteBlur = () => {
        isFocused.current = false;
        let val = parseInt(localM, 10);
        if (isNaN(val)) val = 0;
        val = Math.min(59, Math.max(0, val));
        const formatted = val.toString().padStart(2, '0');
        setLocalM(formatted);
        updateTime(localH, formatted);
    };

    const handleFocus = (e: React.FocusEvent<HTMLInputElement>) => {
        isFocused.current = true;
        e.target.select();
    };

    return (
        <div className="flex items-center border border-gray-200 rounded-lg bg-gray-50 h-10 w-32 relative transition-all hover:border-gray-300 group">
             <div className="absolute inset-y-0 left-0 pl-2 flex items-center pointer-events-none text-gray-400 z-10">
                <Clock size={16} />
            </div>
            <div className="flex items-center pl-8 pr-2 w-full justify-between">
                <input 
                    ref={inputRef}
                    type="text"
                    value={localH} 
                    maxLength={2}
                    onChange={handleHourChange}
                    onBlur={handleHourBlur}
                    onFocus={handleFocus}
                    placeholder="HH"
                    className="bg-transparent outline-none text-gray-700 font-medium text-center w-9 rounded focus:bg-blue-200 transition-colors p-0"
                />
                <span className="text-gray-400 font-medium select-none">:</span>
                <input 
                    ref={minuteRef}
                    type="text"
                    value={localM} 
                    maxLength={2}
                    onChange={handleMinuteChange}
                    onBlur={handleMinuteBlur}
                    onFocus={handleFocus}
                    placeholder="MM"
                    className="bg-transparent outline-none text-gray-700 font-medium text-center w-9 rounded focus:bg-blue-200 transition-colors p-0"
                />
            </div>
        </div>
    );
};

export const EventModal: React.FC<EventModalProps> = ({ 
  isOpen, 
  onClose, 
  onSave, 
  onDelete,
  initialDate, 
  existingEvent 
}) => {
  const [title, setTitle] = useState('');
  const [startDate, setStartDate] = useState(''); 
  const [startTime, setStartTime] = useState('');
  const [endDate, setEndDate] = useState(''); 
  const [endTime, setEndTime] = useState('');
  const [description, setDescription] = useState('');
  const [location, setLocation] = useState('');
  const [region, setRegion] = useState<Region>(Region.IWAMI);
  const [isAllDay, setIsAllDay] = useState(false);
  const [recurrence, setRecurrence] = useState<RecurrenceType>('none');

  const [activeDateField, setActiveDateField] = useState<'start' | 'end' | null>(null);
  const [calendarPos, setCalendarPos] = useState<'top' | 'bottom'>('bottom');

  const startDateRef = useRef<HTMLDivElement>(null);
  const endDateRef = useRef<HTMLDivElement>(null);
  const startHourRef = useRef<HTMLInputElement>(null);
  const endDayInputRef = useRef<HTMLInputElement>(null);
  const endHourRef = useRef<HTMLInputElement>(null);

  useEffect(() => {
    if (isOpen) {
      if (existingEvent) {
        setTitle(existingEvent.title);
        const s = new Date(existingEvent.start);
        const e = new Date(existingEvent.end);
        setStartDate(toDateString(s));
        setStartTime(toTimeString(s));
        setEndDate(toDateString(e));
        setEndTime(toTimeString(e));
        setDescription(existingEvent.description || '');
        setLocation(existingEvent.location || '');
        setRegion(existingEvent.region || Region.IWAMI);
        setIsAllDay(existingEvent.isAllDay);
        setRecurrence(existingEvent.recurrence || 'none');
      } else {
        if (initialDate) {
             const s = new Date(initialDate);
             s.setHours(9, 0, 0, 0); 
             const e = new Date(s);
             e.setHours(10, 0, 0, 0); 
             setStartDate(toDateString(s));
             setStartTime(toTimeString(s));
             setEndDate(toDateString(e));
             setEndTime(toTimeString(e));
        } else {
             setStartDate('');
             setStartTime('');
             setEndDate('');
             setEndTime('');
        }
        setTitle('');
        setDescription('');
        setLocation('');
        setRegion(Region.IWAMI);
        setIsAllDay(false);
        setRecurrence('none');
      }
      setActiveDateField(null);
    }
  }, [isOpen, existingEvent, initialDate]);

  useEffect(() => {
    const handleClickOutside = (event: MouseEvent) => {
        if (activeDateField === 'start' && startDateRef.current && !startDateRef.current.contains(event.target as Node)) {
            setActiveDateField(null);
        } else if (activeDateField === 'end' && endDateRef.current && !endDateRef.current.contains(event.target as Node)) {
            setActiveDateField(null);
        }
    };
    if (activeDateField) {
        document.addEventListener('mousedown', handleClickOutside);
    }
    return () => {
        document.removeEventListener('mousedown', handleClickOutside);
    };
  }, [activeDateField]);

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!startDate || !endDate) return; 

    // Ensure persistence uses standard ISO HH:mm format
    const padTime = (timeStr: string) => {
        const parts = (timeStr || '0:0').split(':');
        const h = parts[0] || '0';
        const m = parts[1] || '0';
        return `${h.padStart(2, '0')}:${m.padStart(2, '0')}`;
    };

    const sTime = isAllDay ? '00:00' : padTime(startTime || '00:00');
    const eTime = isAllDay ? '00:00' : padTime(endTime || '00:00');
    const startIso = `${startDate}T${sTime}:00`;
    const endIso = `${endDate}T${eTime}:00`;

    onSave({
      id: existingEvent?.id || crypto.randomUUID(),
      title,
      start: startIso,
      end: endIso,
      description,
      location,
      region,
      isAllDay,
      recurrence
    });
    onClose();
  };

  const handleDateSelect = (field: 'start' | 'end', newDate: Date) => {
    const dateStr = toDateString(newDate);
    if (field === 'start') {
        setStartDate(dateStr);
        if (!endDate || new Date(dateStr) > new Date(endDate)) {
            setEndDate(dateStr);
        }
    } else {
        setEndDate(dateStr);
    }
    setActiveDateField(null);
  };

  const openCalendar = (field: 'start' | 'end') => {
    const ref = field === 'start' ? startDateRef : endDateRef;
    if (ref.current) {
        const rect = ref.current.getBoundingClientRect();
        const spaceBelow = window.innerHeight - rect.bottom;
        setCalendarPos(spaceBelow < 320 ? 'top' : 'bottom');
    }
    setActiveDateField(field);
  };

  return (
    <Modal 
        isOpen={isOpen} 
        onClose={onClose} 
        title={existingEvent ? 'Edit Event' : 'New Event'}
    >
      <form onSubmit={handleSubmit} className="space-y-4 relative">
        <div className="space-y-1">
            <label className="text-xs font-semibold text-gray-500 uppercase tracking-wider">Event Title</label>
            <div className="relative">
                <div className="absolute inset-y-0 left-0 pl-3 flex items-center pointer-events-none text-gray-400">
                    <Type size={16} />
                </div>
                <input
                    type="text"
                    required
                    value={title}
                    onChange={(e) => setTitle(e.target.value)}
                    placeholder="Add title"
                    className="w-full pl-10 pr-3 py-2 text-gray-700 bg-gray-50 border border-gray-200 rounded-lg focus:ring-2 focus:ring-blue-500 focus:border-transparent outline-none transition-all"
                />
            </div>
        </div>

        <div className="grid grid-cols-1 gap-3">
             <div className="space-y-1">
                <label className="text-xs font-semibold text-gray-500 uppercase tracking-wider">Start</label>
                <div className="flex gap-2">
                     <div 
                        className="relative group flex-grow flex items-center bg-gray-50 border border-gray-200 rounded-lg h-10 pl-10 focus-within:ring-2 focus-within:ring-blue-500 transition-all hover:border-gray-300" 
                        ref={startDateRef}
                     >
                        <div className="absolute inset-y-0 left-0 pl-3 flex items-center pointer-events-none text-gray-400 z-10">
                            <CalendarIcon size={16} />
                        </div>
                        <DateInput 
                            dateStr={startDate}
                            onChange={(iso) => {
                                setStartDate(iso);
                                if (!endDate || new Date(iso) > new Date(endDate)) setEndDate(iso);
                            }}
                            onFocus={() => openCalendar('start')}
                            onComplete={() => isAllDay ? endDayInputRef.current?.focus() : startHourRef.current?.focus()}
                        />
                         {activeDateField === 'start' && (
                            <div className={`absolute left-0 z-50 ${calendarPos === 'top' ? 'bottom-full mb-2' : 'top-full mt-2'}`}>
                                 <MiniCalendar 
                                    initialDate={startDate ? new Date(startDate) : new Date()} 
                                    onSelectDate={(d) => handleDateSelect('start', d)} 
                                    onClose={() => setActiveDateField(null)} 
                                />
                            </div>
                        )}
                     </div>
                     {!isAllDay && (
                        <TimeSelect 
                            value={startTime} 
                            onChange={setStartTime} 
                            inputRef={startHourRef}
                            onComplete={() => endDayInputRef.current?.focus()}
                        />
                     )}
                </div>
            </div>

            <div className="space-y-1">
                <label className="text-xs font-semibold text-gray-500 uppercase tracking-wider">End</label>
                <div className="flex gap-2">
                     <div 
                        className="relative group flex-grow flex items-center bg-gray-50 border border-gray-200 rounded-lg h-10 pl-10 focus-within:ring-2 focus-within:ring-blue-500 transition-all hover:border-gray-300" 
                        ref={endDateRef}
                    >
                        <div className="absolute inset-y-0 left-0 pl-3 flex items-center pointer-events-none text-gray-400 z-10">
                            <CalendarIcon size={16} />
                        </div>
                         <DateInput 
                            dateStr={endDate}
                            onChange={setEndDate}
                            onFocus={() => openCalendar('end')}
                            inputRef={endDayInputRef}
                            onComplete={() => !isAllDay && endHourRef.current?.focus()}
                        />
                        {activeDateField === 'end' && (
                            <div className={`absolute left-0 z-50 ${calendarPos === 'top' ? 'bottom-full mb-2' : 'top-full mt-2'}`}>
                                <MiniCalendar 
                                    initialDate={endDate ? new Date(endDate) : new Date()} 
                                    onSelectDate={(d) => handleDateSelect('end', d)} 
                                    onClose={() => setActiveDateField(null)} 
                                />
                            </div>
                        )}
                    </div>
                    {!isAllDay && (
                         <TimeSelect 
                            value={endTime} 
                            onChange={setEndTime}
                            inputRef={endHourRef} 
                         />
                    )}
                </div>
            </div>
        </div>

        <div className="flex flex-wrap items-center gap-6">
            <div className="flex items-center gap-2">
                <label htmlFor="isAllDay" className="relative flex items-center gap-2 cursor-pointer group">
                    <input 
                        type="checkbox" 
                        id="isAllDay"
                        checked={isAllDay}
                        onChange={(e) => setIsAllDay(e.target.checked)}
                        className="sr-only"
                    />
                    <div className={`
                        w-5 h-5 flex items-center justify-center rounded border-2 transition-all
                        ${isAllDay ? 'bg-white border-gray-900' : 'bg-white border-gray-300 group-hover:border-gray-400'}
                    `}>
                        {isAllDay && <Check size={14} className="text-black stroke-[3.5px]" />}
                    </div>
                    <span className="text-sm text-gray-700 font-medium select-none">All day</span>
                </label>
            </div>

            <div className="flex items-center gap-2">
                <div className="text-gray-400">
                    <Repeat size={16} />
                </div>
                <select
                    value={recurrence}
                    onChange={(e) => setRecurrence(e.target.value as RecurrenceType)}
                    className="bg-transparent border-none text-sm text-gray-700 font-medium focus:ring-0 cursor-pointer outline-none"
                >
                    <option value="none">No repeat</option>
                    <option value="monthly">Monthly</option>
                    <option value="yearly">Yearly</option>
                </select>
            </div>
        </div>

        <div className="space-y-1">
            <label className="text-xs font-semibold text-gray-500 uppercase tracking-wider">Location</label>
            <div className="relative">
                <div className="absolute inset-y-0 left-0 pl-3 flex items-center pointer-events-none text-gray-400">
                    <MapPin size={16} />
                </div>
                <input
                    type="text"
                    value={location}
                    onChange={(e) => setLocation(e.target.value)}
                    placeholder="Add location"
                    className="w-full pl-10 pr-3 py-2 text-gray-700 bg-gray-50 border border-gray-200 rounded-lg focus:ring-2 focus:ring-blue-500 outline-none"
                />
            </div>
        </div>

        <div className="space-y-1">
            <label className="text-xs font-semibold text-gray-500 uppercase tracking-wider">Description</label>
            <div className="relative">
                 <div className="absolute top-3 left-3 flex items-start pointer-events-none text-gray-400">
                    <AlignLeft size={16} />
                </div>
                <textarea
                    value={description}
                    onChange={(e) => setDescription(e.target.value)}
                    placeholder="Add description"
                    className="w-full pl-10 pr-3 py-2 text-gray-700 bg-gray-50 border border-gray-200 rounded-lg focus:ring-2 focus:ring-blue-500 outline-none resize-none h-20"
                />
            </div>
        </div>

        <div className="space-y-1">
            <label className="text-xs font-semibold text-gray-500 uppercase tracking-wider">Region</label>
            <div className="relative">
                <div className="absolute inset-y-0 left-0 pl-3 flex items-center pointer-events-none text-gray-400">
                    <Globe size={16} />
                </div>
                <select
                    value={region}
                    onChange={(e) => setRegion(e.target.value as Region)}
                    className="w-full pl-10 pr-8 py-2 text-gray-700 bg-gray-50 border border-gray-200 rounded-lg focus:ring-2 focus:ring-blue-500 focus:border-transparent outline-none appearance-none transition-all cursor-pointer"
                >
                    {Object.values(Region).map((r) => (
                        <option key={r} value={r}>{r}</option>
                    ))}
                </select>
                 <div className="absolute inset-y-0 right-0 pr-3 flex items-center pointer-events-none text-gray-400">
                    <ChevronDown size={16} />
                 </div>
            </div>
        </div>

        <div className="flex justify-between pt-4 border-t border-gray-100 mt-2">
            {existingEvent ? (
                 <button
                 type="button"
                 onClick={() => {
                     onDelete(existingEvent.id);
                     onClose();
                 }}
                 className="px-4 py-2 text-sm font-medium text-red-600 hover:bg-red-50 rounded-lg transition-colors"
             >
                 Delete
             </button>
            ) : <div />}
            <div className="flex gap-2">
                <button type="button" onClick={onClose} className="px-4 py-2 text-sm font-medium text-gray-600 hover:bg-gray-100 rounded-lg transition-colors">Cancel</button>
                <button type="submit" className="px-4 py-2 text-sm font-medium text-white bg-blue-600 rounded-lg hover:bg-blue-700 transition-colors shadow-sm">Save</button>
            </div>
        </div>
      </form>
    </Modal>
  );
};

import React, { useState, useEffect, useRef } from 'react';
import { Modal } from './Modal';
import { CalendarEvent, Region, RecurrenceType } from '../types';
import { toDateString, toTimeString } from '../utils/dateUtils';
import { Clock, MapPin, AlignLeft, Type, Calendar as CalendarIcon, Globe, ChevronDown, Repeat, Check } from 'lucide-react';
import { MiniCalendar } from './MiniCalendar';

interface EventModalProps {
  isOpen: boolean;
  onClose: () => void;
  onSave: (event: CalendarEvent) => void;
  onDelete: (id: string) => void;
  initialDate?: Date | null;
  existingEvent?: CalendarEvent | null;
}

interface DateInputProps {
    dateStr: string; // ISO YYYY-MM-DD
    onChange: (iso: string) => void;
    onFocus: () => void;
    inputRef?: React.RefObject<HTMLInputElement | null>; 
    onComplete?: () => void; 
}

const DateInput: React.FC<DateInputProps> = ({ dateStr, onChange, onFocus, inputRef, onComplete }) => {
    const [d, setD] = useState('');
    const [m, setM] = useState('');
    const [y, setY] = useState('');

    const monthRef = useRef<HTMLInputElement>(null);
    const yearRef = useRef<HTMLInputElement>(null);
    const isFocused = useRef(false);

    useEffect(() => {
        if (isFocused.current) return;
        if (dateStr) {
            const [year, month, day] = dateStr.split('-');
            setY(year);
            setM(month);
            setD(day);
        } else {
            setD(''); setM(''); setY('');
        }
    }, [dateStr]);

    const updateDate = (day: string, month: string, year: string) => {
        if (day.length >= 1 && month.length >= 1 && year.length === 4) {
             const newDate = new Date(parseInt(year), parseInt(month) - 1, parseInt(day));
             if (newDate.getDate() === parseInt(day) && newDate.getMonth() === parseInt(month) - 1) {
                 onChange(toDateString(newDate));
             }
        }
    };

    const handleDayChange = (e: React.ChangeEvent<HTMLInputElement>) => {
        let val = e.target.value;
        if (!/^\d*$/.test(val)) return;
        setD(val);
        updateDate(val, m, y);
        if (val.length === 2) monthRef.current?.focus();
    };

    const handleMonthChange = (e: React.ChangeEvent<HTMLInputElement>) => {
        let val = e.target.value;
        if (!/^\d*$/.test(val)) return;
        setM(val);
        updateDate(d, val, y);
        if (val.length === 2) yearRef.current?.focus();
    };

    const handleYearChange = (e: React.ChangeEvent<HTMLInputElement>) => {
        let val = e.target.value;
        if (!/^\d*$/.test(val)) return;
        setY(val);
        updateDate(d, m, val);
        if (val.length === 4 && onComplete) {
            onComplete();
        }
    };

    const handleDayBlur = () => {
        isFocused.current = false;
        if (d === '' && dateStr) {
             const [_, __, day] = dateStr.split('-');
             setD(day);
        }
    };

    const handleMonthBlur = () => {
        isFocused.current = false;
        if (m === '' && dateStr) {
             const [_, month, __] = dateStr.split('-');
             setM(month);
        }
    };

    const handleFocus = (e: React.FocusEvent<HTMLInputElement>) => {
        isFocused.current = true;
        e.target.select();
        onFocus();
    };

    return (
        <div className="flex items-center gap-0.5 w-full h-full">
            <input
                ref={inputRef}
                type="text"
                placeholder="DD"
                value={d}
                maxLength={2}
                onChange={handleDayChange}
                onBlur={handleDayBlur}
                onFocus={handleFocus}
                className="bg-transparent outline-none text-gray-700 font-medium text-center w-8 rounded focus:bg-blue-200 transition-colors p-0 placeholder-gray-400"
            />
            <span className="text-gray-400 select-none">/</span>
            <input
                ref={monthRef}
                type="text"
                placeholder="MM"
                value={m}
                maxLength={2}
                onChange={handleMonthChange}
                onBlur={handleMonthBlur}
                onFocus={handleFocus}
                className="bg-transparent outline-none text-gray-700 font-medium text-center w-8 rounded focus:bg-blue-200 transition-colors p-0 placeholder-gray-400"
            />
            <span className="text-gray-400 select-none">/</span>
            <input
                ref={yearRef}
                type="text"
                placeholder="YYYY"
                maxLength={4}
                value={y}
                onChange={handleYearChange}
                onFocus={handleFocus}
                className="bg-transparent outline-none text-gray-700 font-medium text-center w-12 rounded focus:bg-blue-200 transition-colors p-0 placeholder-gray-400"
            />
        </div>
    );
};

const TimeSelect: React.FC<{ 
    value: string; 
    onChange: (val: string) => void; 
    inputRef?: React.RefObject<HTMLInputElement | null>;
    onComplete?: () => void;
}> = ({ value, onChange, inputRef, onComplete }) => {
    const [h = '00', m = '00'] = (value || '00:00').split(':');
    const minuteRef = useRef<HTMLInputElement>(null);
    const isFocused = useRef(false);

    // Initialize with padded values to ensure HH:MM display initially
    const [localH, setLocalH] = useState(h.padStart(2, '0'));
    const [localM, setLocalM] = useState(m.padStart(2, '0'));

    useEffect(() => {
        // Only update from props if not currently editing (prevents overwriting user input)
        if (isFocused.current) return;
        const [newH = '00', newM = '00'] = (value || '00:00').split(':');
        setLocalH(newH.padStart(2, '0'));
        setLocalM(newM.padStart(2, '0'));
    }, [value]);

    const updateTime = (newH: string, newM: string) => {
        // Always emit HH:MM format to parent, but keep local state as-is for editing
        const pad = (v: string) => v.length === 0 ? '00' : v.padStart(2, '0');
        onChange(`${pad(newH)}:${pad(newM)}`);
    };

    const handleHourChange = (e: React.ChangeEvent<HTMLInputElement>) => {
        let val = e.target.value;
        if (!/^\d*$/.test(val)) return;
        setLocalH(val);
        updateTime(val, localM);
        if (val.length === 2) minuteRef.current?.focus();
    };

    const handleHourBlur = () => {
        isFocused.current = false;
        let val = parseInt(localH, 10);
        if (isNaN(val)) val = 0;
        val = Math.min(23, Math.max(0, val));
        const formatted = val.toString().padStart(2, '0');
        setLocalH(formatted);
        updateTime(formatted, localM);
    };

    const handleMinuteChange = (e: React.ChangeEvent<HTMLInputElement>) => {
        let val = e.target.value;
        if (!/^\d*$/.test(val)) return;
        setLocalM(val);
        updateTime(localH, val);
        if (val.length === 2 && onComplete) {
            onComplete();
        }
    };

    const handleMinuteBlur = () => {
        isFocused.current = false;
        let val = parseInt(localM, 10);
        if (isNaN(val)) val = 0;
        val = Math.min(59, Math.max(0, val));
        const formatted = val.toString().padStart(2, '0');
        setLocalM(formatted);
        updateTime(localH, formatted);
    };

    const handleFocus = (e: React.FocusEvent<HTMLInputElement>) => {
        isFocused.current = true;
        e.target.select();
    };

    return (
        <div className="flex items-center border border-gray-200 rounded-lg bg-gray-50 h-10 w-32 relative transition-all hover:border-gray-300 group">
             <div className="absolute inset-y-0 left-0 pl-2 flex items-center pointer-events-none text-gray-400 z-10">
                <Clock size={16} />
            </div>
            <div className="flex items-center pl-8 pr-2 w-full justify-between">
                <input 
                    ref={inputRef}
                    type="text"
                    value={localH} 
                    maxLength={2}
                    onChange={handleHourChange}
                    onBlur={handleHourBlur}
                    onFocus={handleFocus}
                    placeholder="HH"
                    className="bg-transparent outline-none text-gray-700 font-medium text-center w-9 rounded focus:bg-blue-200 transition-colors p-0"
                />
                <span className="text-gray-400 font-medium select-none">:</span>
                <input 
                    ref={minuteRef}
                    type="text"
                    value={localM} 
                    maxLength={2}
                    onChange={handleMinuteChange}
                    onBlur={handleMinuteBlur}
                    onFocus={handleFocus}
                    placeholder="MM"
                    className="bg-transparent outline-none text-gray-700 font-medium text-center w-9 rounded focus:bg-blue-200 transition-colors p-0"
                />
            </div>
        </div>
    );
};

export const EventModal: React.FC<EventModalProps> = ({ 
  isOpen, 
  onClose, 
  onSave, 
  onDelete,
  initialDate, 
  existingEvent 
}) => {
  const [title, setTitle] = useState('');
  const [startDate, setStartDate] = useState(''); 
  const [startTime, setStartTime] = useState('');
  const [endDate, setEndDate] = useState(''); 
  const [endTime, setEndTime] = useState('');
  const [description, setDescription] = useState('');
  const [location, setLocation] = useState('');
  const [region, setRegion] = useState<Region>(Region.IWAMI);
  const [isAllDay, setIsAllDay] = useState(false);
  const [recurrence, setRecurrence] = useState<RecurrenceType>('none');

  const [activeDateField, setActiveDateField] = useState<'start' | 'end' | null>(null);
  const [calendarPos, setCalendarPos] = useState<'top' | 'bottom'>('bottom');

  const startDateRef = useRef<HTMLDivElement>(null);
  const endDateRef = useRef<HTMLDivElement>(null);
  const startHourRef = useRef<HTMLInputElement>(null);
  const endDayInputRef = useRef<HTMLInputElement>(null);
  const endHourRef = useRef<HTMLInputElement>(null);

  useEffect(() => {
    if (isOpen) {
      if (existingEvent) {
        setTitle(existingEvent.title);
        const s = new Date(existingEvent.start);
        const e = new Date(existingEvent.end);
        setStartDate(toDateString(s));
        setStartTime(toTimeString(s));
        setEndDate(toDateString(e));
        setEndTime(toTimeString(e));
        setDescription(existingEvent.description || '');
        setLocation(existingEvent.location || '');
        setRegion(existingEvent.region || Region.IWAMI);
        setIsAllDay(existingEvent.isAllDay);
        setRecurrence(existingEvent.recurrence || 'none');
      } else {
        if (initialDate) {
             const s = new Date(initialDate);
             s.setHours(9, 0, 0, 0); 
             const e = new Date(s);
             e.setHours(10, 0, 0, 0); 
             setStartDate(toDateString(s));
             setStartTime(toTimeString(s));
             setEndDate(toDateString(e));
             setEndTime(toTimeString(e));
        } else {
             setStartDate('');
             setStartTime('');
             setEndDate('');
             setEndTime('');
        }
        setTitle('');
        setDescription('');
        setLocation('');
        setRegion(Region.IWAMI);
        setIsAllDay(false);
        setRecurrence('none');
      }
      setActiveDateField(null);
    }
  }, [isOpen, existingEvent, initialDate]);

  useEffect(() => {
    const handleClickOutside = (event: MouseEvent) => {
        if (activeDateField === 'start' && startDateRef.current && !startDateRef.current.contains(event.target as Node)) {
            setActiveDateField(null);
        } else if (activeDateField === 'end' && endDateRef.current && !endDateRef.current.contains(event.target as Node)) {
            setActiveDateField(null);
        }
    };
    if (activeDateField) {
        document.addEventListener('mousedown', handleClickOutside);
    }
    return () => {
        document.removeEventListener('mousedown', handleClickOutside);
    };
  }, [activeDateField]);

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!startDate || !endDate) return; 

    // Ensure persistence uses standard ISO HH:mm format
    const padTime = (timeStr: string) => {
        const parts = (timeStr || '0:0').split(':');
        const h = parts[0] || '0';
        const m = parts[1] || '0';
        return `${h.padStart(2, '0')}:${m.padStart(2, '0')}`;
    };

    const sTime = isAllDay ? '00:00' : padTime(startTime || '00:00');
    const eTime = isAllDay ? '00:00' : padTime(endTime || '00:00');
    const startIso = `${startDate}T${sTime}:00`;
    const endIso = `${endDate}T${eTime}:00`;

    onSave({
      id: existingEvent?.id || crypto.randomUUID(),
      title,
      start: startIso,
      end: endIso,
      description,
      location,
      region,
      isAllDay,
      recurrence
    });
    onClose();
  };

  const handleDateSelect = (field: 'start' | 'end', newDate: Date) => {
    const dateStr = toDateString(newDate);
    if (field === 'start') {
        setStartDate(dateStr);
        if (!endDate || new Date(dateStr) > new Date(endDate)) {
            setEndDate(dateStr);
        }
    } else {
        setEndDate(dateStr);
    }
    setActiveDateField(null);
  };

  const openCalendar = (field: 'start' | 'end') => {
    const ref = field === 'start' ? startDateRef : endDateRef;
    if (ref.current) {
        const rect = ref.current.getBoundingClientRect();
        const spaceBelow = window.innerHeight - rect.bottom;
        setCalendarPos(spaceBelow < 320 ? 'top' : 'bottom');
    }
    setActiveDateField(field);
  };

  return (
    <Modal 
        isOpen={isOpen} 
        onClose={onClose} 
        title={existingEvent ? 'Edit Event' : 'New Event'}
    >
      <form onSubmit={handleSubmit} className="space-y-4 relative">
        <div className="space-y-1">
            <label className="text-xs font-semibold text-gray-500 uppercase tracking-wider">Event Title</label>
            <div className="relative">
                <div className="absolute inset-y-0 left-0 pl-3 flex items-center pointer-events-none text-gray-400">
                    <Type size={16} />
                </div>
                <input
                    type="text"
                    required
                    value={title}
                    onChange={(e) => setTitle(e.target.value)}
                    placeholder="Add title"
                    className="w-full pl-10 pr-3 py-2 text-gray-700 bg-gray-50 border border-gray-200 rounded-lg focus:ring-2 focus:ring-blue-500 focus:border-transparent outline-none transition-all"
                />
            </div>
        </div>

        <div className="grid grid-cols-1 gap-3">
             <div className="space-y-1">
                <label className="text-xs font-semibold text-gray-500 uppercase tracking-wider">Start</label>
                <div className="flex gap-2">
                     <div 
                        className="relative group flex-grow flex items-center bg-gray-50 border border-gray-200 rounded-lg h-10 pl-10 focus-within:ring-2 focus-within:ring-blue-500 transition-all hover:border-gray-300" 
                        ref={startDateRef}
                     >
                        <div className="absolute inset-y-0 left-0 pl-3 flex items-center pointer-events-none text-gray-400 z-10">
                            <CalendarIcon size={16} />
                        </div>
                        <DateInput 
                            dateStr={startDate}
                            onChange={(iso) => {
                                setStartDate(iso);
                                if (!endDate || new Date(iso) > new Date(endDate)) setEndDate(iso);
                            }}
                            onFocus={() => openCalendar('start')}
                            onComplete={() => isAllDay ? endDayInputRef.current?.focus() : startHourRef.current?.focus()}
                        />
                         {activeDateField === 'start' && (
                            <div className={`absolute left-0 z-50 ${calendarPos === 'top' ? 'bottom-full mb-2' : 'top-full mt-2'}`}>
                                 <MiniCalendar 
                                    initialDate={startDate ? new Date(startDate) : new Date()} 
                                    onSelectDate={(d) => handleDateSelect('start', d)} 
                                    onClose={() => setActiveDateField(null)} 
                                />
                            </div>
                        )}
                     </div>
                     {!isAllDay && (
                        <TimeSelect 
                            value={startTime} 
                            onChange={setStartTime} 
                            inputRef={startHourRef}
                            onComplete={() => endDayInputRef.current?.focus()}
                        />
                     )}
                </div>
            </div>

            <div className="space-y-1">
                <label className="text-xs font-semibold text-gray-500 uppercase tracking-wider">End</label>
                <div className="flex gap-2">
                     <div 
                        className="relative group flex-grow flex items-center bg-gray-50 border border-gray-200 rounded-lg h-10 pl-10 focus-within:ring-2 focus-within:ring-blue-500 transition-all hover:border-gray-300" 
                        ref={endDateRef}
                    >
                        <div className="absolute inset-y-0 left-0 pl-3 flex items-center pointer-events-none text-gray-400 z-10">
                            <CalendarIcon size={16} />
                        </div>
                         <DateInput 
                            dateStr={endDate}
                            onChange={setEndDate}
                            onFocus={() => openCalendar('end')}
                            inputRef={endDayInputRef}
                            onComplete={() => !isAllDay && endHourRef.current?.focus()}
                        />
                        {activeDateField === 'end' && (
                            <div className={`absolute left-0 z-50 ${calendarPos === 'top' ? 'bottom-full mb-2' : 'top-full mt-2'}`}>
                                <MiniCalendar 
                                    initialDate={endDate ? new Date(endDate) : new Date()} 
                                    onSelectDate={(d) => handleDateSelect('end', d)} 
                                    onClose={() => setActiveDateField(null)} 
                                />
                            </div>
                        )}
                    </div>
                    {!isAllDay && (
                         <TimeSelect 
                            value={endTime} 
                            onChange={setEndTime}
                            inputRef={endHourRef} 
                         />
                    )}
                </div>
            </div>
        </div>

        <div className="flex flex-wrap items-center gap-6">
            <div className="flex items-center gap-2">
                <label htmlFor="isAllDay" className="relative flex items-center gap-2 cursor-pointer group">
                    <input 
                        type="checkbox" 
                        id="isAllDay"
                        checked={isAllDay}
                        onChange={(e) => setIsAllDay(e.target.checked)}
                        className="sr-only"
                    />
                    <div className={`
                        w-5 h-5 flex items-center justify-center rounded border-2 transition-all
                        ${isAllDay ? 'bg-white border-gray-900' : 'bg-white border-gray-300 group-hover:border-gray-400'}
                    `}>
                        {isAllDay && <Check size={14} className="text-black stroke-[3.5px]" />}
                    </div>
                    <span className="text-sm text-gray-700 font-medium select-none">All day</span>
                </label>
            </div>

            <div className="flex items-center gap-2">
                <div className="text-gray-400">
                    <Repeat size={16} />
                </div>
                <select
                    value={recurrence}
                    onChange={(e) => setRecurrence(e.target.value as RecurrenceType)}
                    className="bg-transparent border-none text-sm text-gray-700 font-medium focus:ring-0 cursor-pointer outline-none"
                >
                    <option value="none">No repeat</option>
                    <option value="monthly">Monthly</option>
                    <option value="yearly">Yearly</option>
                </select>
            </div>
        </div>

        <div className="space-y-1">
            <label className="text-xs font-semibold text-gray-500 uppercase tracking-wider">Location</label>
            <div className="relative">
                <div className="absolute inset-y-0 left-0 pl-3 flex items-center pointer-events-none text-gray-400">
                    <MapPin size={16} />
                </div>
                <input
                    type="text"
                    value={location}
                    onChange={(e) => setLocation(e.target.value)}
                    placeholder="Add location"
                    className="w-full pl-10 pr-3 py-2 text-gray-700 bg-gray-50 border border-gray-200 rounded-lg focus:ring-2 focus:ring-blue-500 outline-none"
                />
            </div>
        </div>

        <div className="space-y-1">
            <label className="text-xs font-semibold text-gray-500 uppercase tracking-wider">Description</label>
            <div className="relative">
                 <div className="absolute top-3 left-3 flex items-start pointer-events-none text-gray-400">
                    <AlignLeft size={16} />
                </div>
                <textarea
                    value={description}
                    onChange={(e) => setDescription(e.target.value)}
                    placeholder="Add description"
                    className="w-full pl-10 pr-3 py-2 text-gray-700 bg-gray-50 border border-gray-200 rounded-lg focus:ring-2 focus:ring-blue-500 outline-none resize-none h-20"
                />
            </div>
        </div>

        <div className="space-y-1">
            <label className="text-xs font-semibold text-gray-500 uppercase tracking-wider">Region</label>
            <div className="relative">
                <div className="absolute inset-y-0 left-0 pl-3 flex items-center pointer-events-none text-gray-400">
                    <Globe size={16} />
                </div>
                <select
                    value={region}
                    onChange={(e) => setRegion(e.target.value as Region)}
                    className="w-full pl-10 pr-8 py-2 text-gray-700 bg-gray-50 border border-gray-200 rounded-lg focus:ring-2 focus:ring-blue-500 focus:border-transparent outline-none appearance-none transition-all cursor-pointer"
                >
                    {Object.values(Region).map((r) => (
                        <option key={r} value={r}>{r}</option>
                    ))}
                </select>
                 <div className="absolute inset-y-0 right-0 pr-3 flex items-center pointer-events-none text-gray-400">
                    <ChevronDown size={16} />
                 </div>
            </div>
        </div>

        <div className="flex justify-between pt-4 border-t border-gray-100 mt-2">
            {existingEvent ? (
                 <button
                 type="button"
                 onClick={() => {
                     onDelete(existingEvent.id);
                     onClose();
                 }}
                 className="px-4 py-2 text-sm font-medium text-red-600 hover:bg-red-50 rounded-lg transition-colors"
             >
                 Delete
             </button>
            ) : <div />}
            <div className="flex gap-2">
                <button type="button" onClick={onClose} className="px-4 py-2 text-sm font-medium text-gray-600 hover:bg-gray-100 rounded-lg transition-colors">Cancel</button>
                <button type="submit" className="px-4 py-2 text-sm font-medium text-white bg-blue-600 rounded-lg hover:bg-blue-700 transition-colors shadow-sm">Save</button>
            </div>
        </div>
      </form>
    </Modal>
  );
};

import React, { useState, useEffect, useRef } from 'react';
import { Modal } from './Modal';
import { CalendarEvent, Region, RecurrenceType } from '../types';
import { toDateString, toTimeString } from '../utils/dateUtils';
import { Clock, MapPin, AlignLeft, Type, Calendar as CalendarIcon, Globe, ChevronDown, Repeat, Check } from 'lucide-react';
import { MiniCalendar } from './MiniCalendar';

interface EventModalProps {
  isOpen: boolean;
  onClose: () => void;
  onSave: (event: CalendarEvent) => void;
  onDelete: (id: string) => void;
  initialDate?: Date | null;
  existingEvent?: CalendarEvent | null;
}

interface DateInputProps {
    dateStr: string; // ISO YYYY-MM-DD
    onChange: (iso: string) => void;
    onFocus: () => void;
    inputRef?: React.RefObject<HTMLInputElement | null>; 
    onComplete?: () => void; 
}

const DateInput: React.FC<DateInputProps> = ({ dateStr, onChange, onFocus, inputRef, onComplete }) => {
    const [d, setD] = useState('');
    const [m, setM] = useState('');
    const [y, setY] = useState('');

    const monthRef = useRef<HTMLInputElement>(null);
    const yearRef = useRef<HTMLInputElement>(null);
    const isFocused = useRef(false);

    useEffect(() => {
        if (isFocused.current) return;
        if (dateStr) {
            const [year, month, day] = dateStr.split('-');
            setY(year);
            setM(month);
            setD(day);
        } else {
            setD(''); setM(''); setY('');
        }
    }, [dateStr]);

    const updateDate = (day: string, month: string, year: string) => {
        if (day.length >= 1 && month.length >= 1 && year.length === 4) {
             const newDate = new Date(parseInt(year), parseInt(month) - 1, parseInt(day));
             if (newDate.getDate() === parseInt(day) && newDate.getMonth() === parseInt(month) - 1) {
                 onChange(toDateString(newDate));
             }
        }
    };

    const handleDayChange = (e: React.ChangeEvent<HTMLInputElement>) => {
        let val = e.target.value;
        if (!/^\d*$/.test(val)) return;
        setD(val);
        updateDate(val, m, y);
        if (val.length === 2) monthRef.current?.focus();
    };

    const handleMonthChange = (e: React.ChangeEvent<HTMLInputElement>) => {
        let val = e.target.value;
        if (!/^\d*$/.test(val)) return;
        setM(val);
        updateDate(d, val, y);
        if (val.length === 2) yearRef.current?.focus();
    };

    const handleYearChange = (e: React.ChangeEvent<HTMLInputElement>) => {
        let val = e.target.value;
        if (!/^\d*$/.test(val)) return;
        setY(val);
        updateDate(d, m, val);
        if (val.length === 4 && onComplete) {
            onComplete();
        }
    };

    const handleDayBlur = () => {
        isFocused.current = false;
        if (d === '' && dateStr) {
             const [_, __, day] = dateStr.split('-');
             setD(day);
        }
    };

    const handleMonthBlur = () => {
        isFocused.current = false;
        if (m === '' && dateStr) {
             const [_, month, __] = dateStr.split('-');
             setM(month);
        }
    };

    const handleFocus = (e: React.FocusEvent<HTMLInputElement>) => {
        isFocused.current = true;
        e.target.select();
        onFocus();
    };

    return (
        <div className="flex items-center gap-0.5 w-full h-full">
            <input
                ref={inputRef}
                type="text"
                placeholder="DD"
                value={d}
                maxLength={2}
                onChange={handleDayChange}
                onBlur={handleDayBlur}
                onFocus={handleFocus}
                className="bg-transparent outline-none text-gray-700 font-medium text-center w-8 rounded focus:bg-blue-200 transition-colors p-0 placeholder-gray-400"
            />
            <span className="text-gray-400 select-none">/</span>
            <input
                ref={monthRef}
                type="text"
                placeholder="MM"
                value={m}
                maxLength={2}
                onChange={handleMonthChange}
                onBlur={handleMonthBlur}
                onFocus={handleFocus}
                className="bg-transparent outline-none text-gray-700 font-medium text-center w-8 rounded focus:bg-blue-200 transition-colors p-0 placeholder-gray-400"
            />
            <span className="text-gray-400 select-none">/</span>
            <input
                ref={yearRef}
                type="text"
                placeholder="YYYY"
                maxLength={4}
                value={y}
                onChange={handleYearChange}
                onFocus={handleFocus}
                className="bg-transparent outline-none text-gray-700 font-medium text-center w-12 rounded focus:bg-blue-200 transition-colors p-0 placeholder-gray-400"
            />
        </div>
    );
};

const TimeSelect: React.FC<{ 
    value: string; 
    onChange: (val: string) => void; 
    inputRef?: React.RefObject<HTMLInputElement | null>;
    onComplete?: () => void;
}> = ({ value, onChange, inputRef, onComplete }) => {
    const [h = '', m = ''] = (value || '0:0').split(':');
    const minuteRef = useRef<HTMLInputElement>(null);
    const isFocused = useRef(false);

    // Initialize without forced padding
    const [localH, setLocalH] = useState(h);
    const [localM, setLocalM] = useState(m);

    useEffect(() => {
        // Only update from props if not currently editing (prevents overwriting user input)
        if (isFocused.current) return;
        const [newH = '0', newM = '0'] = (value || '0:0').split(':');
        setLocalH(newH);
        setLocalM(newM);
    }, [value]);

    const updateTime = (newH: string, newM: string) => {
        // Pass the raw values; parent or submit handler handles final formatting
        onChange(`${newH}:${newM}`);
    };

    const handleHourChange = (e: React.ChangeEvent<HTMLInputElement>) => {
        let val = e.target.value;
        if (!/^\d*$/.test(val)) return;
        setLocalH(val);
        updateTime(val, localM);
        if (val.length === 2) minuteRef.current?.focus();
    };

    const handleHourBlur = () => {
        isFocused.current = false;
        let val = parseInt(localH, 10);
        if (isNaN(val)) val = 0;
        val = Math.min(23, Math.max(0, val));
        // Convert back to string without padding
        const formatted = val.toString();
        setLocalH(formatted);
        updateTime(formatted, localM);
    };

    const handleMinuteChange = (e: React.ChangeEvent<HTMLInputElement>) => {
        let val = e.target.value;
        if (!/^\d*$/.test(val)) return;
        setLocalM(val);
        updateTime(localH, val);
        if (val.length === 2 && onComplete) {
            onComplete();
        }
    };

    const handleMinuteBlur = () => {
        isFocused.current = false;
        let val = parseInt(localM, 10);
        if (isNaN(val)) val = 0;
        val = Math.min(59, Math.max(0, val));
        // Convert back to string without padding
        const formatted = val.toString();
        setLocalM(formatted);
        updateTime(localH, formatted);
    };

    const handleFocus = (e: React.FocusEvent<HTMLInputElement>) => {
        isFocused.current = true;
        e.target.select();
    };

    return (
        <div className="flex items-center border border-gray-200 rounded-lg bg-gray-50 h-10 w-32 relative transition-all hover:border-gray-300 group">
             <div className="absolute inset-y-0 left-0 pl-2 flex items-center pointer-events-none text-gray-400 z-10">
                <Clock size={16} />
            </div>
            <div className="flex items-center pl-8 pr-2 w-full justify-between">
                <input 
                    ref={inputRef}
                    type="text"
                    value={localH} 
                    maxLength={2}
                    onChange={handleHourChange}
                    onBlur={handleHourBlur}
                    onFocus={handleFocus}
                    placeholder="HH"
                    className="bg-transparent outline-none text-gray-700 font-medium text-center w-9 rounded focus:bg-blue-200 transition-colors p-0"
                />
                <span className="text-gray-400 font-medium select-none">:</span>
                <input 
                    ref={minuteRef}
                    type="text"
                    value={localM} 
                    maxLength={2}
                    onChange={handleMinuteChange}
                    onBlur={handleMinuteBlur}
                    onFocus={handleFocus}
                    placeholder="MM"
                    className="bg-transparent outline-none text-gray-700 font-medium text-center w-9 rounded focus:bg-blue-200 transition-colors p-0"
                />
            </div>
        </div>
    );
};

export const EventModal: React.FC<EventModalProps> = ({ 
  isOpen, 
  onClose, 
  onSave, 
  onDelete,
  initialDate, 
  existingEvent 
}) => {
  const [title, setTitle] = useState('');
  const [startDate, setStartDate] = useState(''); 
  const [startTime, setStartTime] = useState('');
  const [endDate, setEndDate] = useState(''); 
  const [endTime, setEndTime] = useState('');
  const [description, setDescription] = useState('');
  const [location, setLocation] = useState('');
  const [region, setRegion] = useState<Region>(Region.IWAMI);
  const [isAllDay, setIsAllDay] = useState(false);
  const [recurrence, setRecurrence] = useState<RecurrenceType>('none');

  const [activeDateField, setActiveDateField] = useState<'start' | 'end' | null>(null);
  const [calendarPos, setCalendarPos] = useState<'top' | 'bottom'>('bottom');

  const startDateRef = useRef<HTMLDivElement>(null);
  const endDateRef = useRef<HTMLDivElement>(null);
  const startHourRef = useRef<HTMLInputElement>(null);
  const endDayInputRef = useRef<HTMLInputElement>(null);
  const endHourRef = useRef<HTMLInputElement>(null);

  useEffect(() => {
    if (isOpen) {
      if (existingEvent) {
        setTitle(existingEvent.title);
        const s = new Date(existingEvent.start);
        const e = new Date(existingEvent.end);
        setStartDate(toDateString(s));
        setStartTime(toTimeString(s));
        setEndDate(toDateString(e));
        setEndTime(toTimeString(e));
        setDescription(existingEvent.description || '');
        setLocation(existingEvent.location || '');
        setRegion(existingEvent.region || Region.IWAMI);
        setIsAllDay(existingEvent.isAllDay);
        setRecurrence(existingEvent.recurrence || 'none');
      } else {
        if (initialDate) {
             const s = new Date(initialDate);
             s.setHours(9, 0, 0, 0); 
             const e = new Date(s);
             e.setHours(10, 0, 0, 0); 
             setStartDate(toDateString(s));
             setStartTime(toTimeString(s));
             setEndDate(toDateString(e));
             setEndTime(toTimeString(e));
        } else {
             setStartDate('');
             setStartTime('');
             setEndDate('');
             setEndTime('');
        }
        setTitle('');
        setDescription('');
        setLocation('');
        setRegion(Region.IWAMI);
        setIsAllDay(false);
        setRecurrence('none');
      }
      setActiveDateField(null);
    }
  }, [isOpen, existingEvent, initialDate]);

  useEffect(() => {
    const handleClickOutside = (event: MouseEvent) => {
        if (activeDateField === 'start' && startDateRef.current && !startDateRef.current.contains(event.target as Node)) {
            setActiveDateField(null);
        } else if (activeDateField === 'end' && endDateRef.current && !endDateRef.current.contains(event.target as Node)) {
            setActiveDateField(null);
        }
    };
    if (activeDateField) {
        document.addEventListener('mousedown', handleClickOutside);
    }
    return () => {
        document.removeEventListener('mousedown', handleClickOutside);
    };
  }, [activeDateField]);

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!startDate || !endDate) return; 

    // Ensure persistence uses standard ISO HH:mm format
    const padTime = (timeStr: string) => {
        const parts = (timeStr || '0:0').split(':');
        const h = parts[0] || '0';
        const m = parts[1] || '0';
        return `${h.padStart(2, '0')}:${m.padStart(2, '0')}`;
    };

    const sTime = isAllDay ? '00:00' : padTime(startTime || '00:00');
    const eTime = isAllDay ? '00:00' : padTime(endTime || '00:00');
    const startIso = `${startDate}T${sTime}:00`;
    const endIso = `${endDate}T${eTime}:00`;

    onSave({
      id: existingEvent?.id || crypto.randomUUID(),
      title,
      start: startIso,
      end: endIso,
      description,
      location,
      region,
      isAllDay,
      recurrence
    });
    onClose();
  };

  const handleDateSelect = (field: 'start' | 'end', newDate: Date) => {
    const dateStr = toDateString(newDate);
    if (field === 'start') {
        setStartDate(dateStr);
        if (!endDate || new Date(dateStr) > new Date(endDate)) {
            setEndDate(dateStr);
        }
    } else {
        setEndDate(dateStr);
    }
    setActiveDateField(null);
  };

  const openCalendar = (field: 'start' | 'end') => {
    const ref = field === 'start' ? startDateRef : endDateRef;
    if (ref.current) {
        const rect = ref.current.getBoundingClientRect();
        const spaceBelow = window.innerHeight - rect.bottom;
        setCalendarPos(spaceBelow < 320 ? 'top' : 'bottom');
    }
    setActiveDateField(field);
  };

  return (
    <Modal 
        isOpen={isOpen} 
        onClose={onClose} 
        title={existingEvent ? 'Edit Event' : 'New Event'}
    >
      <form onSubmit={handleSubmit} className="space-y-4 relative">
        <div className="space-y-1">
            <label className="text-xs font-semibold text-gray-500 uppercase tracking-wider">Event Title</label>
            <div className="relative">
                <div className="absolute inset-y-0 left-0 pl-3 flex items-center pointer-events-none text-gray-400">
                    <Type size={16} />
                </div>
                <input
                    type="text"
                    required
                    value={title}
                    onChange={(e) => setTitle(e.target.value)}
                    placeholder="Add title"
                    className="w-full pl-10 pr-3 py-2 text-gray-700 bg-gray-50 border border-gray-200 rounded-lg focus:ring-2 focus:ring-blue-500 focus:border-transparent outline-none transition-all"
                />
            </div>
        </div>

        <div className="grid grid-cols-1 gap-3">
             <div className="space-y-1">
                <label className="text-xs font-semibold text-gray-500 uppercase tracking-wider">Start</label>
                <div className="flex gap-2">
                     <div 
                        className="relative group flex-grow flex items-center bg-gray-50 border border-gray-200 rounded-lg h-10 pl-10 focus-within:ring-2 focus-within:ring-blue-500 transition-all hover:border-gray-300" 
                        ref={startDateRef}
                     >
                        <div className="absolute inset-y-0 left-0 pl-3 flex items-center pointer-events-none text-gray-400 z-10">
                            <CalendarIcon size={16} />
                        </div>
                        <DateInput 
                            dateStr={startDate}
                            onChange={(iso) => {
                                setStartDate(iso);
                                if (!endDate || new Date(iso) > new Date(endDate)) setEndDate(iso);
                            }}
                            onFocus={() => openCalendar('start')}
                            onComplete={() => isAllDay ? endDayInputRef.current?.focus() : startHourRef.current?.focus()}
                        />
                         {activeDateField === 'start' && (
                            <div className={`absolute left-0 z-50 ${calendarPos === 'top' ? 'bottom-full mb-2' : 'top-full mt-2'}`}>
                                 <MiniCalendar 
                                    initialDate={startDate ? new Date(startDate) : new Date()} 
                                    onSelectDate={(d) => handleDateSelect('start', d)} 
                                    onClose={() => setActiveDateField(null)} 
                                />
                            </div>
                        )}
                     </div>
                     {!isAllDay && (
                        <TimeSelect 
                            value={startTime} 
                            onChange={setStartTime} 
                            inputRef={startHourRef}
                            onComplete={() => endDayInputRef.current?.focus()}
                        />
                     )}
                </div>
            </div>

            <div className="space-y-1">
                <label className="text-xs font-semibold text-gray-500 uppercase tracking-wider">End</label>
                <div className="flex gap-2">
                     <div 
                        className="relative group flex-grow flex items-center bg-gray-50 border border-gray-200 rounded-lg h-10 pl-10 focus-within:ring-2 focus-within:ring-blue-500 transition-all hover:border-gray-300" 
                        ref={endDateRef}
                    >
                        <div className="absolute inset-y-0 left-0 pl-3 flex items-center pointer-events-none text-gray-400 z-10">
                            <CalendarIcon size={16} />
                        </div>
                         <DateInput 
                            dateStr={endDate}
                            onChange={setEndDate}
                            onFocus={() => openCalendar('end')}
                            inputRef={endDayInputRef}
                            onComplete={() => !isAllDay && endHourRef.current?.focus()}
                        />
                        {activeDateField === 'end' && (
                            <div className={`absolute left-0 z-50 ${calendarPos === 'top' ? 'bottom-full mb-2' : 'top-full mt-2'}`}>
                                <MiniCalendar 
                                    initialDate={endDate ? new Date(endDate) : new Date()} 
                                    onSelectDate={(d) => handleDateSelect('end', d)} 
                                    onClose={() => setActiveDateField(null)} 
                                />
                            </div>
                        )}
                    </div>
                    {!isAllDay && (
                         <TimeSelect 
                            value={endTime} 
                            onChange={setEndTime}
                            inputRef={endHourRef} 
                         />
                    )}
                </div>
            </div>
        </div>

        <div className="flex flex-wrap items-center gap-6">
            <div className="flex items-center gap-2">
                <label htmlFor="isAllDay" className="relative flex items-center gap-2 cursor-pointer group">
                    <input 
                        type="checkbox" 
                        id="isAllDay"
                        checked={isAllDay}
                        onChange={(e) => setIsAllDay(e.target.checked)}
                        className="sr-only"
                    />
                    <div className={`
                        w-5 h-5 flex items-center justify-center rounded border-2 transition-all
                        ${isAllDay ? 'bg-white border-gray-900' : 'bg-white border-gray-300 group-hover:border-gray-400'}
                    `}>
                        {isAllDay && <Check size={14} className="text-black stroke-[3.5px]" />}
                    </div>
                    <span className="text-sm text-gray-700 font-medium select-none">All day</span>
                </label>
            </div>

            <div className="flex items-center gap-2">
                <div className="text-gray-400">
                    <Repeat size={16} />
                </div>
                <select
                    value={recurrence}
                    onChange={(e) => setRecurrence(e.target.value as RecurrenceType)}
                    className="bg-transparent border-none text-sm text-gray-700 font-medium focus:ring-0 cursor-pointer outline-none"
                >
                    <option value="none">No repeat</option>
                    <option value="monthly">Monthly</option>
                    <option value="yearly">Yearly</option>
                </select>
            </div>
        </div>

        <div className="space-y-1">
            <label className="text-xs font-semibold text-gray-500 uppercase tracking-wider">Location</label>
            <div className="relative">
                <div className="absolute inset-y-0 left-0 pl-3 flex items-center pointer-events-none text-gray-400">
                    <MapPin size={16} />
                </div>
                <input
                    type="text"
                    value={location}
                    onChange={(e) => setLocation(e.target.value)}
                    placeholder="Add location"
                    className="w-full pl-10 pr-3 py-2 text-gray-700 bg-gray-50 border border-gray-200 rounded-lg focus:ring-2 focus:ring-blue-500 outline-none"
                />
            </div>
        </div>

        <div className="space-y-1">
            <label className="text-xs font-semibold text-gray-500 uppercase tracking-wider">Description</label>
            <div className="relative">
                 <div className="absolute top-3 left-3 flex items-start pointer-events-none text-gray-400">
                    <AlignLeft size={16} />
                </div>
                <textarea
                    value={description}
                    onChange={(e) => setDescription(e.target.value)}
                    placeholder="Add description"
                    className="w-full pl-10 pr-3 py-2 text-gray-700 bg-gray-50 border border-gray-200 rounded-lg focus:ring-2 focus:ring-blue-500 outline-none resize-none h-20"
                />
            </div>
        </div>

        <div className="space-y-1">
            <label className="text-xs font-semibold text-gray-500 uppercase tracking-wider">Region</label>
            <div className="relative">
                <div className="absolute inset-y-0 left-0 pl-3 flex items-center pointer-events-none text-gray-400">
                    <Globe size={16} />
                </div>
                <select
                    value={region}
                    onChange={(e) => setRegion(e.target.value as Region)}
                    className="w-full pl-10 pr-8 py-2 text-gray-700 bg-gray-50 border border-gray-200 rounded-lg focus:ring-2 focus:ring-blue-500 focus:border-transparent outline-none appearance-none transition-all cursor-pointer"
                >
                    {Object.values(Region).map((r) => (
                        <option key={r} value={r}>{r}</option>
                    ))}
                </select>
                 <div className="absolute inset-y-0 right-0 pr-3 flex items-center pointer-events-none text-gray-400">
                    <ChevronDown size={16} />
                 </div>
            </div>
        </div>

        <div className="flex justify-between pt-4 border-t border-gray-100 mt-2">
            {existingEvent ? (
                 <button
                 type="button"
                 onClick={() => {
                     onDelete(existingEvent.id);
                     onClose();
                 }}
                 className="px-4 py-2 text-sm font-medium text-red-600 hover:bg-red-50 rounded-lg transition-colors"
             >
                 Delete
             </button>
            ) : <div />}
            <div className="flex gap-2">
                <button type="button" onClick={onClose} className="px-4 py-2 text-sm font-medium text-gray-600 hover:bg-gray-100 rounded-lg transition-colors">Cancel</button>
                <button type="submit" className="px-4 py-2 text-sm font-medium text-white bg-blue-600 rounded-lg hover:bg-blue-700 transition-colors shadow-sm">Save</button>
            </div>
        </div>
      </form>
    </Modal>
  );
};

import React, { useState, useEffect, useRef } from 'react';
import { Modal } from './Modal';
import { CalendarEvent, Region, RecurrenceType } from '../types';
import { toDateString, toTimeString } from '../utils/dateUtils';
import { Clock, MapPin, AlignLeft, Type, Calendar as CalendarIcon, Globe, ChevronDown, Repeat, Check } from 'lucide-react';
import { MiniCalendar } from './MiniCalendar';

interface EventModalProps {
  isOpen: boolean;
  onClose: () => void;
  onSave: (event: CalendarEvent) => void;
  onDelete: (id: string) => void;
  initialDate?: Date | null;
  existingEvent?: CalendarEvent | null;
}

interface DateInputProps {
    dateStr: string; // ISO YYYY-MM-DD
    onChange: (iso: string) => void;
    onFocus: () => void;
    inputRef?: React.RefObject<HTMLInputElement | null>; 
    onComplete?: () => void; 
}

const DateInput: React.FC<DateInputProps> = ({ dateStr, onChange, onFocus, inputRef, onComplete }) => {
    const [d, setD] = useState('');
    const [m, setM] = useState('');
    const [y, setY] = useState('');

    const monthRef = useRef<HTMLInputElement>(null);
    const yearRef = useRef<HTMLInputElement>(null);
    const isFocused = useRef(false);

    useEffect(() => {
        if (isFocused.current) return;
        if (dateStr) {
            const [year, month, day] = dateStr.split('-');
            setY(year);
            setM(month);
            setD(day);
        } else {
            setD(''); setM(''); setY('');
        }
    }, [dateStr]);

    const updateDate = (day: string, month: string, year: string) => {
        if (day.length >= 1 && month.length >= 1 && year.length === 4) {
             const newDate = new Date(parseInt(year), parseInt(month) - 1, parseInt(day));
             if (newDate.getDate() === parseInt(day) && newDate.getMonth() === parseInt(month) - 1) {
                 onChange(toDateString(newDate));
             }
        }
    };

    const handleDayChange = (e: React.ChangeEvent<HTMLInputElement>) => {
        let val = e.target.value;
        if (!/^\d*$/.test(val)) return;
        setD(val);
        updateDate(val, m, y);
        if (val.length === 2) monthRef.current?.focus();
    };

    const handleMonthChange = (e: React.ChangeEvent<HTMLInputElement>) => {
        let val = e.target.value;
        if (!/^\d*$/.test(val)) return;
        setM(val);
        updateDate(d, val, y);
        if (val.length === 2) yearRef.current?.focus();
    };

    const handleYearChange = (e: React.ChangeEvent<HTMLInputElement>) => {
        let val = e.target.value;
        if (!/^\d*$/.test(val)) return;
        setY(val);
        updateDate(d, m, val);
        if (val.length === 4 && onComplete) {
            onComplete();
        }
    };

    const handleDayBlur = () => {
        isFocused.current = false;
        if (d === '' && dateStr) {
             const [_, __, day] = dateStr.split('-');
             setD(day);
        }
    };

    const handleMonthBlur = () => {
        isFocused.current = false;
        if (m === '' && dateStr) {
             const [_, month, __] = dateStr.split('-');
             setM(month);
        }
    };

    const handleFocus = (e: React.FocusEvent<HTMLInputElement>) => {
        isFocused.current = true;
        e.target.select();
        onFocus();
    };

    return (
        <div className="flex items-center gap-0.5 w-full h-full">
            <input
                ref={inputRef}
                type="text"
                placeholder="DD"
                value={d}
                maxLength={2}
                onChange={handleDayChange}
                onBlur={handleDayBlur}
                onFocus={handleFocus}
                className="bg-transparent outline-none text-gray-700 font-medium text-center w-8 rounded focus:bg-blue-200 transition-colors p-0 placeholder-gray-400"
            />
            <span className="text-gray-400 select-none">/</span>
            <input
                ref={monthRef}
                type="text"
                placeholder="MM"
                value={m}
                maxLength={2}
                onChange={handleMonthChange}
                onBlur={handleMonthBlur}
                onFocus={handleFocus}
                className="bg-transparent outline-none text-gray-700 font-medium text-center w-8 rounded focus:bg-blue-200 transition-colors p-0 placeholder-gray-400"
            />
            <span className="text-gray-400 select-none">/</span>
            <input
                ref={yearRef}
                type="text"
                placeholder="YYYY"
                maxLength={4}
                value={y}
                onChange={handleYearChange}
                onFocus={handleFocus}
                className="bg-transparent outline-none text-gray-700 font-medium text-center w-12 rounded focus:bg-blue-200 transition-colors p-0 placeholder-gray-400"
            />
        </div>
    );
};

const TimeSelect: React.FC<{ 
    value: string; 
    onChange: (val: string) => void; 
    inputRef?: React.RefObject<HTMLInputElement | null>;
    onComplete?: () => void;
}> = ({ value, onChange, inputRef, onComplete }) => {
    const [h = '', m = ''] = (value || '0:0').split(':');
    const minuteRef = useRef<HTMLInputElement>(null);
    const isFocused = useRef(false);

    // Initialize without forced padding
    const [localH, setLocalH] = useState(h);
    const [localM, setLocalM] = useState(m);

    useEffect(() => {
        // Only update from props if not currently editing (prevents overwriting user input)
        if (isFocused.current) return;
        const [newH = '0', newM = '0'] = (value || '0:0').split(':');
        setLocalH(newH);
        setLocalM(newM);
    }, [value]);

    const updateTime = (newH: string, newM: string) => {
        // Pass the raw values; parent or submit handler handles final formatting
        onChange(`${newH}:${newM}`);
    };

    const handleHourChange = (e: React.ChangeEvent<HTMLInputElement>) => {
        let val = e.target.value;
        if (!/^\d*$/.test(val)) return;
        setLocalH(val);
        updateTime(val, localM);
        if (val.length === 2) minuteRef.current?.focus();
    };

    const handleHourBlur = () => {
        isFocused.current = false;
        let val = parseInt(localH, 10);
        if (isNaN(val)) {
            setLocalH('0');
            updateTime('0', localM);
            return;
        }

        const clamped = Math.min(23, Math.max(0, val));
        // Only update if value changed (clamping) to preserve leading zeros if typed
        if (clamped !== val) {
            setLocalH(clamped.toString());
            updateTime(clamped.toString(), localM);
        }
    };

    const handleMinuteChange = (e: React.ChangeEvent<HTMLInputElement>) => {
        let val = e.target.value;
        if (!/^\d*$/.test(val)) return;
        setLocalM(val);
        updateTime(localH, val);
        if (val.length === 2 && onComplete) {
            onComplete();
        }
    };

    const handleMinuteBlur = () => {
        isFocused.current = false;
        let val = parseInt(localM, 10);
        if (isNaN(val)) {
            setLocalM('0');
            updateTime(localH, '0');
            return;
        }

        const clamped = Math.min(59, Math.max(0, val));
        if (clamped !== val) {
            setLocalM(clamped.toString());
            updateTime(localH, clamped.toString());
        }
    };

    const handleFocus = (e: React.FocusEvent<HTMLInputElement>) => {
        isFocused.current = true;
        e.target.select();
    };

    return (
        <div className="flex items-center border border-gray-200 rounded-lg bg-gray-50 h-10 w-32 relative transition-all hover:border-gray-300 group">
             <div className="absolute inset-y-0 left-0 pl-2 flex items-center pointer-events-none text-gray-400 z-10">
                <Clock size={16} />
            </div>
            <div className="flex items-center pl-8 pr-2 w-full justify-between">
                <input 
                    ref={inputRef}
                    type="text"
                    value={localH} 
                    maxLength={2}
                    onChange={handleHourChange}
                    onBlur={handleHourBlur}
                    onFocus={handleFocus}
                    placeholder="HH"
                    className="bg-transparent outline-none text-gray-700 font-medium text-center w-9 rounded focus:bg-blue-200 transition-colors p-0"
                />
                <span className="text-gray-400 font-medium select-none">:</span>
                <input 
                    ref={minuteRef}
                    type="text"
                    value={localM} 
                    maxLength={2}
                    onChange={handleMinuteChange}
                    onBlur={handleMinuteBlur}
                    onFocus={handleFocus}
                    placeholder="MM"
                    className="bg-transparent outline-none text-gray-700 font-medium text-center w-9 rounded focus:bg-blue-200 transition-colors p-0"
                />
            </div>
        </div>
    );
};

export const EventModal: React.FC<EventModalProps> = ({ 
  isOpen, 
  onClose, 
  onSave, 
  onDelete,
  initialDate, 
  existingEvent 
}) => {
  const [title, setTitle] = useState('');
  const [startDate, setStartDate] = useState(''); 
  const [startTime, setStartTime] = useState('');
  const [endDate, setEndDate] = useState(''); 
  const [endTime, setEndTime] = useState('');
  const [description, setDescription] = useState('');
  const [location, setLocation] = useState('');
  const [region, setRegion] = useState<Region>(Region.IWAMI);
  const [isAllDay, setIsAllDay] = useState(false);
  const [recurrence, setRecurrence] = useState<RecurrenceType>('none');

  const [activeDateField, setActiveDateField] = useState<'start' | 'end' | null>(null);
  const [calendarPos, setCalendarPos] = useState<'top' | 'bottom'>('bottom');

  const startDateRef = useRef<HTMLDivElement>(null);
  const endDateRef = useRef<HTMLDivElement>(null);
  const startHourRef = useRef<HTMLInputElement>(null);
  const endDayInputRef = useRef<HTMLInputElement>(null);
  const endHourRef = useRef<HTMLInputElement>(null);

  useEffect(() => {
    if (isOpen) {
      if (existingEvent) {
        setTitle(existingEvent.title);
        const s = new Date(existingEvent.start);
        const e = new Date(existingEvent.end);
        setStartDate(toDateString(s));
        setStartTime(toTimeString(s));
        setEndDate(toDateString(e));
        setEndTime(toTimeString(e));
        setDescription(existingEvent.description || '');
        setLocation(existingEvent.location || '');
        setRegion(existingEvent.region || Region.IWAMI);
        setIsAllDay(existingEvent.isAllDay);
        setRecurrence(existingEvent.recurrence || 'none');
      } else {
        if (initialDate) {
             const s = new Date(initialDate);
             s.setHours(9, 0, 0, 0); 
             const e = new Date(s);
             e.setHours(10, 0, 0, 0); 
             setStartDate(toDateString(s));
             setStartTime(toTimeString(s));
             setEndDate(toDateString(e));
             setEndTime(toTimeString(e));
        } else {
             setStartDate('');
             setStartTime('');
             setEndDate('');
             setEndTime('');
        }
        setTitle('');
        setDescription('');
        setLocation('');
        setRegion(Region.IWAMI);
        setIsAllDay(false);
        setRecurrence('none');
      }
      setActiveDateField(null);
    }
  }, [isOpen, existingEvent, initialDate]);

  useEffect(() => {
    const handleClickOutside = (event: MouseEvent) => {
        if (activeDateField === 'start' && startDateRef.current && !startDateRef.current.contains(event.target as Node)) {
            setActiveDateField(null);
        } else if (activeDateField === 'end' && endDateRef.current && !endDateRef.current.contains(event.target as Node)) {
            setActiveDateField(null);
        }
    };
    if (activeDateField) {
        document.addEventListener('mousedown', handleClickOutside);
    }
    return () => {
        document.removeEventListener('mousedown', handleClickOutside);
    };
  }, [activeDateField]);

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!startDate || !endDate) return; 

    // Ensure persistence uses standard ISO HH:mm format
    const padTime = (timeStr: string) => {
        const parts = (timeStr || '0:0').split(':');
        const h = parts[0] || '0';
        const m = parts[1] || '0';
        return `${h.padStart(2, '0')}:${m.padStart(2, '0')}`;
    };

    const sTime = isAllDay ? '00:00' : padTime(startTime || '00:00');
    const eTime = isAllDay ? '00:00' : padTime(endTime || '00:00');
    const startIso = `${startDate}T${sTime}:00`;
    const endIso = `${endDate}T${eTime}:00`;

    onSave({
      id: existingEvent?.id || crypto.randomUUID(),
      title,
      start: startIso,
      end: endIso,
      description,
      location,
      region,
      isAllDay,
      recurrence
    });
    onClose();
  };

  const handleDateSelect = (field: 'start' | 'end', newDate: Date) => {
    const dateStr = toDateString(newDate);
    if (field === 'start') {
        setStartDate(dateStr);
        if (!endDate || new Date(dateStr) > new Date(endDate)) {
            setEndDate(dateStr);
        }
    } else {
        setEndDate(dateStr);
    }
    setActiveDateField(null);
  };

  const openCalendar = (field: 'start' | 'end') => {
    const ref = field === 'start' ? startDateRef : endDateRef;
    if (ref.current) {
        const rect = ref.current.getBoundingClientRect();
        const spaceBelow = window.innerHeight - rect.bottom;
        setCalendarPos(spaceBelow < 320 ? 'top' : 'bottom');
    }
    setActiveDateField(field);
  };

  return (
    <Modal 
        isOpen={isOpen} 
        onClose={onClose} 
        title={existingEvent ? 'Edit Event' : 'New Event'}
    >
      <form onSubmit={handleSubmit} className="space-y-4 relative">
        <div className="space-y-1">
            <label className="text-xs font-semibold text-gray-500 uppercase tracking-wider">Event Title</label>
            <div className="relative">
                <div className="absolute inset-y-0 left-0 pl-3 flex items-center pointer-events-none text-gray-400">
                    <Type size={16} />
                </div>
                <input
                    type="text"
                    required
                    value={title}
                    onChange={(e) => setTitle(e.target.value)}
                    placeholder="Add title"
                    className="w-full pl-10 pr-3 py-2 text-gray-700 bg-gray-50 border border-gray-200 rounded-lg focus:ring-2 focus:ring-blue-500 focus:border-transparent outline-none transition-all"
                />
            </div>
        </div>

        <div className="grid grid-cols-1 gap-3">
             <div className="space-y-1">
                <label className="text-xs font-semibold text-gray-500 uppercase tracking-wider">Start</label>
                <div className="flex gap-2">
                     <div 
                        className="relative group flex-grow flex items-center bg-gray-50 border border-gray-200 rounded-lg h-10 pl-10 focus-within:ring-2 focus-within:ring-blue-500 transition-all hover:border-gray-300" 
                        ref={startDateRef}
                     >
                        <div className="absolute inset-y-0 left-0 pl-3 flex items-center pointer-events-none text-gray-400 z-10">
                            <CalendarIcon size={16} />
                        </div>
                        <DateInput 
                            dateStr={startDate}
                            onChange={(iso) => {
                                setStartDate(iso);
                                if (!endDate || new Date(iso) > new Date(endDate)) setEndDate(iso);
                            }}
                            onFocus={() => openCalendar('start')}
                            onComplete={() => isAllDay ? endDayInputRef.current?.focus() : startHourRef.current?.focus()}
                        />
                         {activeDateField === 'start' && (
                            <div className={`absolute left-0 z-50 ${calendarPos === 'top' ? 'bottom-full mb-2' : 'top-full mt-2'}`}>
                                 <MiniCalendar 
                                    initialDate={startDate ? new Date(startDate) : new Date()} 
                                    onSelectDate={(d) => handleDateSelect('start', d)} 
                                    onClose={() => setActiveDateField(null)} 
                                />
                            </div>
                        )}
                     </div>
                     {!isAllDay && (
                        <TimeSelect 
                            value={startTime} 
                            onChange={setStartTime} 
                            inputRef={startHourRef}
                            onComplete={() => endDayInputRef.current?.focus()}
                        />
                     )}
                </div>
            </div>

            <div className="space-y-1">
                <label className="text-xs font-semibold text-gray-500 uppercase tracking-wider">End</label>
                <div className="flex gap-2">
                     <div 
                        className="relative group flex-grow flex items-center bg-gray-50 border border-gray-200 rounded-lg h-10 pl-10 focus-within:ring-2 focus-within:ring-blue-500 transition-all hover:border-gray-300" 
                        ref={endDateRef}
                    >
                        <div className="absolute inset-y-0 left-0 pl-3 flex items-center pointer-events-none text-gray-400 z-10">
                            <CalendarIcon size={16} />
                        </div>
                         <DateInput 
                            dateStr={endDate}
                            onChange={setEndDate}
                            onFocus={() => openCalendar('end')}
                            inputRef={endDayInputRef}
                            onComplete={() => !isAllDay && endHourRef.current?.focus()}
                        />
                        {activeDateField === 'end' && (
                            <div className={`absolute left-0 z-50 ${calendarPos === 'top' ? 'bottom-full mb-2' : 'top-full mt-2'}`}>
                                <MiniCalendar 
                                    initialDate={endDate ? new Date(endDate) : new Date()} 
                                    onSelectDate={(d) => handleDateSelect('end', d)} 
                                    onClose={() => setActiveDateField(null)} 
                                />
                            </div>
                        )}
                    </div>
                    {!isAllDay && (
                         <TimeSelect 
                            value={endTime} 
                            onChange={setEndTime}
                            inputRef={endHourRef} 
                         />
                    )}
                </div>
            </div>
        </div>

        <div className="flex flex-wrap items-center gap-6">
            <div className="flex items-center gap-2">
                <label htmlFor="isAllDay" className="relative flex items-center gap-2 cursor-pointer group">
                    <input 
                        type="checkbox" 
                        id="isAllDay"
                        checked={isAllDay}
                        onChange={(e) => setIsAllDay(e.target.checked)}
                        className="sr-only"
                    />
                    <div className={`
                        w-5 h-5 flex items-center justify-center rounded border-2 transition-all
                        ${isAllDay ? 'bg-white border-gray-900' : 'bg-white border-gray-300 group-hover:border-gray-400'}
                    `}>
                        {isAllDay && <Check size={14} className="text-black stroke-[3.5px]" />}
                    </div>
                    <span className="text-sm text-gray-700 font-medium select-none">All day</span>
                </label>
            </div>

            <div className="flex items-center gap-2">
                <div className="text-gray-400">
                    <Repeat size={16} />
                </div>
                <select
                    value={recurrence}
                    onChange={(e) => setRecurrence(e.target.value as RecurrenceType)}
                    className="bg-transparent border-none text-sm text-gray-700 font-medium focus:ring-0 cursor-pointer outline-none"
                >
                    <option value="none">No repeat</option>
                    <option value="monthly">Monthly</option>
                    <option value="yearly">Yearly</option>
                </select>
            </div>
        </div>

        <div className="space-y-1">
            <label className="text-xs font-semibold text-gray-500 uppercase tracking-wider">Location</label>
            <div className="relative">
                <div className="absolute inset-y-0 left-0 pl-3 flex items-center pointer-events-none text-gray-400">
                    <MapPin size={16} />
                </div>
                <input
                    type="text"
                    value={location}
                    onChange={(e) => setLocation(e.target.value)}
                    placeholder="Add location"
                    className="w-full pl-10 pr-3 py-2 text-gray-700 bg-gray-50 border border-gray-200 rounded-lg focus:ring-2 focus:ring-blue-500 outline-none"
                />
            </div>
        </div>

        <div className="space-y-1">
            <label className="text-xs font-semibold text-gray-500 uppercase tracking-wider">Description</label>
            <div className="relative">
                 <div className="absolute top-3 left-3 flex items-start pointer-events-none text-gray-400">
                    <AlignLeft size={16} />
                </div>
                <textarea
                    value={description}
                    onChange={(e) => setDescription(e.target.value)}
                    placeholder="Add description"
                    className="w-full pl-10 pr-3 py-2 text-gray-700 bg-gray-50 border border-gray-200 rounded-lg focus:ring-2 focus:ring-blue-500 outline-none resize-none h-20"
                />
            </div>
        </div>

        <div className="space-y-1">
            <label className="text-xs font-semibold text-gray-500 uppercase tracking-wider">Region</label>
            <div className="relative">
                <div className="absolute inset-y-0 left-0 pl-3 flex items-center pointer-events-none text-gray-400">
                    <Globe size={16} />
                </div>
                <select
                    value={region}
                    onChange={(e) => setRegion(e.target.value as Region)}
                    className="w-full pl-10 pr-8 py-2 text-gray-700 bg-gray-50 border border-gray-200 rounded-lg focus:ring-2 focus:ring-blue-500 focus:border-transparent outline-none appearance-none transition-all cursor-pointer"
                >
                    {Object.values(Region).map((r) => (
                        <option key={r} value={r}>{r}</option>
                    ))}
                </select>
                 <div className="absolute inset-y-0 right-0 pr-3 flex items-center pointer-events-none text-gray-400">
                    <ChevronDown size={16} />
                 </div>
            </div>
        </div>

        <div className="flex justify-between pt-4 border-t border-gray-100 mt-2">
            {existingEvent ? (
                 <button
                 type="button"
                 onClick={() => {
                     onDelete(existingEvent.id);
                     onClose();
                 }}
                 className="px-4 py-2 text-sm font-medium text-red-600 hover:bg-red-50 rounded-lg transition-colors"
             >
                 Delete
             </button>
            ) : <div />}
            <div className="flex gap-2">
                <button type="button" onClick={onClose} className="px-4 py-2 text-sm font-medium text-gray-600 hover:bg-gray-100 rounded-lg transition-colors">Cancel</button>
                <button type="submit" className="px-4 py-2 text-sm font-medium text-white bg-blue-600 rounded-lg hover:bg-blue-700 transition-colors shadow-sm">Save</button>
            </div>
        </div>
      </form>
    </Modal>
  );
};

import React, { useState, useEffect, useRef } from 'react';
import { Modal } from './Modal';
import { CalendarEvent, Region, RecurrenceType } from '../types';
import { toDateString, toTimeString } from '../utils/dateUtils';
import { Clock, MapPin, AlignLeft, Type, Calendar as CalendarIcon, Globe, ChevronDown, Repeat, Check } from 'lucide-react';
import { MiniCalendar } from './MiniCalendar';

interface EventModalProps {
  isOpen: boolean;
  onClose: () => void;
  onSave: (event: CalendarEvent) => void;
  onDelete: (id: string) => void;
  initialDate?: Date | null;
  existingEvent?: CalendarEvent | null;
}

interface DateInputProps {
    dateStr: string; // ISO YYYY-MM-DD
    onChange: (iso: string) => void;
    onFocus: () => void;
    inputRef?: React.RefObject<HTMLInputElement | null>; 
    onComplete?: () => void; 
}

const DateInput: React.FC<DateInputProps> = ({ dateStr, onChange, onFocus, inputRef, onComplete }) => {
    const [d, setD] = useState('');
    const [m, setM] = useState('');
    const [y, setY] = useState('');

    const monthRef = useRef<HTMLInputElement>(null);
    const yearRef = useRef<HTMLInputElement>(null);
    const isFocused = useRef(false);

    useEffect(() => {
        if (isFocused.current) return;
        if (dateStr) {
            const [year, month, day] = dateStr.split('-');
            setY(year);
            setM(month);
            setD(day);
        } else {
            setD(''); setM(''); setY('');
        }
    }, [dateStr]);

    const updateDate = (day: string, month: string, year: string) => {
        if (day.length >= 1 && month.length >= 1 && year.length === 4) {
             const newDate = new Date(parseInt(year), parseInt(month) - 1, parseInt(day));
             if (newDate.getDate() === parseInt(day) && newDate.getMonth() === parseInt(month) - 1) {
                 onChange(toDateString(newDate));
             }
        }
    };

    const handleDayChange = (e: React.ChangeEvent<HTMLInputElement>) => {
        let val = e.target.value;
        if (!/^\d*$/.test(val)) return;
        setD(val);
        updateDate(val, m, y);
        if (val.length === 2) monthRef.current?.focus();
    };

    const handleMonthChange = (e: React.ChangeEvent<HTMLInputElement>) => {
        let val = e.target.value;
        if (!/^\d*$/.test(val)) return;
        setM(val);
        updateDate(d, val, y);
        if (val.length === 2) yearRef.current?.focus();
    };

    const handleYearChange = (e: React.ChangeEvent<HTMLInputElement>) => {
        let val = e.target.value;
        if (!/^\d*$/.test(val)) return;
        setY(val);
        updateDate(d, m, val);
        if (val.length === 4 && onComplete) {
            onComplete();
        }
    };

    const handleDayBlur = () => {
        isFocused.current = false;
        if (d === '' && dateStr) {
             const [_, __, day] = dateStr.split('-');
             setD(day);
        }
    };

    const handleMonthBlur = () => {
        isFocused.current = false;
        if (m === '' && dateStr) {
             const [_, month, __] = dateStr.split('-');
             setM(month);
        }
    };

    const handleFocus = (e: React.FocusEvent<HTMLInputElement>) => {
        isFocused.current = true;
        e.target.select();
        onFocus();
    };

    return (
        <div className="flex items-center gap-0.5 w-full h-full">
            <input
                ref={inputRef}
                type="text"
                placeholder="DD"
                value={d}
                maxLength={2}
                onChange={handleDayChange}
                onBlur={handleDayBlur}
                onFocus={handleFocus}
                className="bg-transparent outline-none text-gray-700 font-medium text-center w-8 rounded focus:bg-blue-200 transition-colors p-0 placeholder-gray-400"
            />
            <span className="text-gray-400 select-none">/</span>
            <input
                ref={monthRef}
                type="text"
                placeholder="MM"
                value={m}
                maxLength={2}
                onChange={handleMonthChange}
                onBlur={handleMonthBlur}
                onFocus={handleFocus}
                className="bg-transparent outline-none text-gray-700 font-medium text-center w-8 rounded focus:bg-blue-200 transition-colors p-0 placeholder-gray-400"
            />
            <span className="text-gray-400 select-none">/</span>
            <input
                ref={yearRef}
                type="text"
                placeholder="YYYY"
                maxLength={4}
                value={y}
                onChange={handleYearChange}
                onFocus={handleFocus}
                className="bg-transparent outline-none text-gray-700 font-medium text-center w-12 rounded focus:bg-blue-200 transition-colors p-0 placeholder-gray-400"
            />
        </div>
    );
};

const TimeSelect: React.FC<{ 
    value: string; 
    onChange: (val: string) => void; 
    inputRef?: React.RefObject<HTMLInputElement | null>;
    onComplete?: () => void;
}> = ({ value, onChange, inputRef, onComplete }) => {
    const [h = '', m = ''] = (value || '0:0').split(':');
    const minuteRef = useRef<HTMLInputElement>(null);
    const isFocused = useRef(false);

    // Initialize without forced padding
    const [localH, setLocalH] = useState(h);
    const [localM, setLocalM] = useState(m);

    useEffect(() => {
        // Only update from props if not currently editing (prevents overwriting user input)
        if (isFocused.current) return;
        const [newH = '0', newM = '0'] = (value || '0:0').split(':');
        setLocalH(newH);
        setLocalM(newM);
    }, [value]);

    const updateTime = (newH: string, newM: string) => {
        // Pass the raw values; parent or submit handler handles final formatting
        onChange(`${newH}:${newM}`);
    };

    const handleHourChange = (e: React.ChangeEvent<HTMLInputElement>) => {
        let val = e.target.value;
        if (!/^\d*$/.test(val)) return;
        setLocalH(val);
        updateTime(val, localM);
        if (val.length === 2) minuteRef.current?.focus();
    };

    const handleHourBlur = () => {
        isFocused.current = false;
        let val = parseInt(localH, 10);
        if (isNaN(val)) val = 0;

        val = Math.min(23, Math.max(0, val));

        // Pad with 0 if length < 2
        const formatted = val.toString().padStart(2, '0');

        setLocalH(formatted);
        updateTime(formatted, localM);
    };

    const handleMinuteChange = (e: React.ChangeEvent<HTMLInputElement>) => {
        let val = e.target.value;
        if (!/^\d*$/.test(val)) return;
        setLocalM(val);
        updateTime(localH, val);
        if (val.length === 2 && onComplete) {
            onComplete();
        }
    };

    const handleMinuteBlur = () => {
        isFocused.current = false;
        let val = parseInt(localM, 10);
        if (isNaN(val)) val = 0;

        val = Math.min(59, Math.max(0, val));

        // Pad with 0 if length < 2
        const formatted = val.toString().padStart(2, '0');

        setLocalM(formatted);
        updateTime(localH, formatted);
    };

    const handleFocus = (e: React.FocusEvent<HTMLInputElement>) => {
        isFocused.current = true;
        e.target.select();
    };

    return (
        <div className="flex items-center border border-gray-200 rounded-lg bg-gray-50 h-10 w-32 relative transition-all hover:border-gray-300 group">
             <div className="absolute inset-y-0 left-0 pl-2 flex items-center pointer-events-none text-gray-400 z-10">
                <Clock size={16} />
            </div>
            <div className="flex items-center pl-8 pr-2 w-full justify-between">
                <input 
                    ref={inputRef}
                    type="text"
                    value={localH} 
                    maxLength={2}
                    onChange={handleHourChange}
                    onBlur={handleHourBlur}
                    onFocus={handleFocus}
                    placeholder="HH"
                    className="bg-transparent outline-none text-gray-700 font-medium text-center w-9 rounded focus:bg-blue-200 transition-colors p-0"
                />
                <span className="text-gray-400 font-medium select-none">:</span>
                <input 
                    ref={minuteRef}
                    type="text"
                    value={localM} 
                    maxLength={2}
                    onChange={handleMinuteChange}
                    onBlur={handleMinuteBlur}
                    onFocus={handleFocus}
                    placeholder="MM"
                    className="bg-transparent outline-none text-gray-700 font-medium text-center w-9 rounded focus:bg-blue-200 transition-colors p-0"
                />
            </div>
        </div>
    );
};

export const EventModal: React.FC<EventModalProps> = ({ 
  isOpen, 
  onClose, 
  onSave, 
  onDelete,
  initialDate, 
  existingEvent 
}) => {
  const [title, setTitle] = useState('');
  const [startDate, setStartDate] = useState(''); 
  const [startTime, setStartTime] = useState('');
  const [endDate, setEndDate] = useState(''); 
  const [endTime, setEndTime] = useState('');
  const [description, setDescription] = useState('');
  const [location, setLocation] = useState('');
  const [region, setRegion] = useState<Region>(Region.IWAMI);
  const [isAllDay, setIsAllDay] = useState(false);
  const [recurrence, setRecurrence] = useState<RecurrenceType>('none');

  const [activeDateField, setActiveDateField] = useState<'start' | 'end' | null>(null);
  const [calendarPos, setCalendarPos] = useState<'top' | 'bottom'>('bottom');

  const startDateRef = useRef<HTMLDivElement>(null);
  const endDateRef = useRef<HTMLDivElement>(null);
  const startHourRef = useRef<HTMLInputElement>(null);
  const endDayInputRef = useRef<HTMLInputElement>(null);
  const endHourRef = useRef<HTMLInputElement>(null);

  useEffect(() => {
    if (isOpen) {
      if (existingEvent) {
        setTitle(existingEvent.title);
        const s = new Date(existingEvent.start);
        const e = new Date(existingEvent.end);
        setStartDate(toDateString(s));
        setStartTime(toTimeString(s));
        setEndDate(toDateString(e));
        setEndTime(toTimeString(e));
        setDescription(existingEvent.description || '');
        setLocation(existingEvent.location || '');
        setRegion(existingEvent.region || Region.IWAMI);
        setIsAllDay(existingEvent.isAllDay);
        setRecurrence(existingEvent.recurrence || 'none');
      } else {
        if (initialDate) {
             const s = new Date(initialDate);
             s.setHours(9, 0, 0, 0); 
             const e = new Date(s);
             e.setHours(10, 0, 0, 0); 
             setStartDate(toDateString(s));
             setStartTime(toTimeString(s));
             setEndDate(toDateString(e));
             setEndTime(toTimeString(e));
        } else {
             setStartDate('');
             setStartTime('');
             setEndDate('');
             setEndTime('');
        }
        setTitle('');
        setDescription('');
        setLocation('');
        setRegion(Region.IWAMI);
        setIsAllDay(false);
        setRecurrence('none');
      }
      setActiveDateField(null);
    }
  }, [isOpen, existingEvent, initialDate]);

  useEffect(() => {
    const handleClickOutside = (event: MouseEvent) => {
        if (activeDateField === 'start' && startDateRef.current && !startDateRef.current.contains(event.target as Node)) {
            setActiveDateField(null);
        } else if (activeDateField === 'end' && endDateRef.current && !endDateRef.current.contains(event.target as Node)) {
            setActiveDateField(null);
        }
    };
    if (activeDateField) {
        document.addEventListener('mousedown', handleClickOutside);
    }
    return () => {
        document.removeEventListener('mousedown', handleClickOutside);
    };
  }, [activeDateField]);

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!startDate || !endDate) return; 

    // Ensure persistence uses standard ISO HH:mm format
    const padTime = (timeStr: string) => {
        const parts = (timeStr || '0:0').split(':');
        const h = parts[0] || '0';
        const m = parts[1] || '0';
        return `${h.padStart(2, '0')}:${m.padStart(2, '0')}`;
    };

    const sTime = isAllDay ? '00:00' : padTime(startTime || '00:00');
    const eTime = isAllDay ? '00:00' : padTime(endTime || '00:00');
    const startIso = `${startDate}T${sTime}:00`;
    const endIso = `${endDate}T${eTime}:00`;

    onSave({
      id: existingEvent?.id || crypto.randomUUID(),
      title,
      start: startIso,
      end: endIso,
      description,
      location,
      region,
      isAllDay,
      recurrence
    });
    onClose();
  };

  const handleDateSelect = (field: 'start' | 'end', newDate: Date) => {
    const dateStr = toDateString(newDate);
    if (field === 'start') {
        setStartDate(dateStr);
        if (!endDate || new Date(dateStr) > new Date(endDate)) {
            setEndDate(dateStr);
        }
    } else {
        setEndDate(dateStr);
    }
    setActiveDateField(null);
  };

  const openCalendar = (field: 'start' | 'end') => {
    const ref = field === 'start' ? startDateRef : endDateRef;
    if (ref.current) {
        const rect = ref.current.getBoundingClientRect();
        const spaceBelow = window.innerHeight - rect.bottom;
        setCalendarPos(spaceBelow < 320 ? 'top' : 'bottom');
    }
    setActiveDateField(field);
  };

  return (
    <Modal 
        isOpen={isOpen} 
        onClose={onClose} 
        title={existingEvent ? 'Edit Event' : 'New Event'}
    >
      <form onSubmit={handleSubmit} className="space-y-4 relative">
        <div className="space-y-1">
            <label className="text-xs font-semibold text-gray-500 uppercase tracking-wider">Event Title</label>
            <div className="relative">
                <div className="absolute inset-y-0 left-0 pl-3 flex items-center pointer-events-none text-gray-400">
                    <Type size={16} />
                </div>
                <input
                    type="text"
                    required
                    value={title}
                    onChange={(e) => setTitle(e.target.value)}
                    placeholder="Add title"
                    className="w-full pl-10 pr-3 py-2 text-gray-700 bg-gray-50 border border-gray-200 rounded-lg focus:ring-2 focus:ring-blue-500 focus:border-transparent outline-none transition-all"
                />
            </div>
        </div>

        <div className="grid grid-cols-1 gap-3">
             <div className="space-y-1">
                <label className="text-xs font-semibold text-gray-500 uppercase tracking-wider">Start</label>
                <div className="flex gap-2">
                     <div 
                        className="relative group flex-grow flex items-center bg-gray-50 border border-gray-200 rounded-lg h-10 pl-10 focus-within:ring-2 focus-within:ring-blue-500 transition-all hover:border-gray-300" 
                        ref={startDateRef}
                     >
                        <div className="absolute inset-y-0 left-0 pl-3 flex items-center pointer-events-none text-gray-400 z-10">
                            <CalendarIcon size={16} />
                        </div>
                        <DateInput 
                            dateStr={startDate}
                            onChange={(iso) => {
                                setStartDate(iso);
                                if (!endDate || new Date(iso) > new Date(endDate)) setEndDate(iso);
                            }}
                            onFocus={() => openCalendar('start')}
                            onComplete={() => isAllDay ? endDayInputRef.current?.focus() : startHourRef.current?.focus()}
                        />
                         {activeDateField === 'start' && (
                            <div className={`absolute left-0 z-50 ${calendarPos === 'top' ? 'bottom-full mb-2' : 'top-full mt-2'}`}>
                                 <MiniCalendar 
                                    initialDate={startDate ? new Date(startDate) : new Date()} 
                                    onSelectDate={(d) => handleDateSelect('start', d)} 
                                    onClose={() => setActiveDateField(null)} 
                                />
                            </div>
                        )}
                     </div>
                     {!isAllDay && (
                        <TimeSelect 
                            value={startTime} 
                            onChange={setStartTime} 
                            inputRef={startHourRef}
                            onComplete={() => endDayInputRef.current?.focus()}
                        />
                     )}
                </div>
            </div>

            <div className="space-y-1">
                <label className="text-xs font-semibold text-gray-500 uppercase tracking-wider">End</label>
                <div className="flex gap-2">
                     <div 
                        className="relative group flex-grow flex items-center bg-gray-50 border border-gray-200 rounded-lg h-10 pl-10 focus-within:ring-2 focus-within:ring-blue-500 transition-all hover:border-gray-300" 
                        ref={endDateRef}
                    >
                        <div className="absolute inset-y-0 left-0 pl-3 flex items-center pointer-events-none text-gray-400 z-10">
                            <CalendarIcon size={16} />
                        </div>
                         <DateInput 
                            dateStr={endDate}
                            onChange={setEndDate}
                            onFocus={() => openCalendar('end')}
                            inputRef={endDayInputRef}
                            onComplete={() => !isAllDay && endHourRef.current?.focus()}
                        />
                        {activeDateField === 'end' && (
                            <div className={`absolute left-0 z-50 ${calendarPos === 'top' ? 'bottom-full mb-2' : 'top-full mt-2'}`}>
                                <MiniCalendar 
                                    initialDate={endDate ? new Date(endDate) : new Date()} 
                                    onSelectDate={(d) => handleDateSelect('end', d)} 
                                    onClose={() => setActiveDateField(null)} 
                                />
                            </div>
                        )}
                    </div>
                    {!isAllDay && (
                         <TimeSelect 
                            value={endTime} 
                            onChange={setEndTime}
                            inputRef={endHourRef} 
                         />
                    )}
                </div>
            </div>
        </div>

        <div className="flex flex-wrap items-center gap-6">
            <div className="flex items-center gap-2">
                <label htmlFor="isAllDay" className="relative flex items-center gap-2 cursor-pointer group">
                    <input 
                        type="checkbox" 
                        id="isAllDay"
                        checked={isAllDay}
                        onChange={(e) => setIsAllDay(e.target.checked)}
                        className="sr-only"
                    />
                    <div className={`
                        w-5 h-5 flex items-center justify-center rounded border-2 transition-all
                        ${isAllDay ? 'bg-white border-gray-900' : 'bg-white border-gray-300 group-hover:border-gray-400'}
                    `}>
                        {isAllDay && <Check size={14} className="text-black stroke-[3.5px]" />}
                    </div>
                    <span className="text-sm text-gray-700 font-medium select-none">All day</span>
                </label>
            </div>

            <div className="flex items-center gap-2">
                <div className="text-gray-400">
                    <Repeat size={16} />
                </div>
                <select
                    value={recurrence}
                    onChange={(e) => setRecurrence(e.target.value as RecurrenceType)}
                    className="bg-transparent border-none text-sm text-gray-700 font-medium focus:ring-0 cursor-pointer outline-none"
                >
                    <option value="none">No repeat</option>
                    <option value="monthly">Monthly</option>
                    <option value="yearly">Yearly</option>
                </select>
            </div>
        </div>

        <div className="space-y-1">
            <label className="text-xs font-semibold text-gray-500 uppercase tracking-wider">Location</label>
            <div className="relative">
                <div className="absolute inset-y-0 left-0 pl-3 flex items-center pointer-events-none text-gray-400">
                    <MapPin size={16} />
                </div>
                <input
                    type="text"
                    value={location}
                    onChange={(e) => setLocation(e.target.value)}
                    placeholder="Add location"
                    className="w-full pl-10 pr-3 py-2 text-gray-700 bg-gray-50 border border-gray-200 rounded-lg focus:ring-2 focus:ring-blue-500 outline-none"
                />
            </div>
        </div>

        <div className="space-y-1">
            <label className="text-xs font-semibold text-gray-500 uppercase tracking-wider">Description</label>
            <div className="relative">
                 <div className="absolute top-3 left-3 flex items-start pointer-events-none text-gray-400">
                    <AlignLeft size={16} />
                </div>
                <textarea
                    value={description}
                    onChange={(e) => setDescription(e.target.value)}
                    placeholder="Add description"
                    className="w-full pl-10 pr-3 py-2 text-gray-700 bg-gray-50 border border-gray-200 rounded-lg focus:ring-2 focus:ring-blue-500 outline-none resize-none h-20"
                />
            </div>
        </div>

        <div className="space-y-1">
            <label className="text-xs font-semibold text-gray-500 uppercase tracking-wider">Region</label>
            <div className="relative">
                <div className="absolute inset-y-0 left-0 pl-3 flex items-center pointer-events-none text-gray-400">
                    <Globe size={16} />
                </div>
                <select
                    value={region}
                    onChange={(e) => setRegion(e.target.value as Region)}
                    className="w-full pl-10 pr-8 py-2 text-gray-700 bg-gray-50 border border-gray-200 rounded-lg focus:ring-2 focus:ring-blue-500 focus:border-transparent outline-none appearance-none transition-all cursor-pointer"
                >
                    {Object.values(Region).map((r) => (
                        <option key={r} value={r}>{r}</option>
                    ))}
                </select>
                 <div className="absolute inset-y-0 right-0 pr-3 flex items-center pointer-events-none text-gray-400">
                    <ChevronDown size={16} />
                 </div>
            </div>
        </div>

        <div className="flex justify-between pt-4 border-t border-gray-100 mt-2">
            {existingEvent ? (
                 <button
                 type="button"
                 onClick={() => {
                     onDelete(existingEvent.id);
                     onClose();
                 }}
                 className="px-4 py-2 text-sm font-medium text-red-600 hover:bg-red-50 rounded-lg transition-colors"
             >
                 Delete
             </button>
            ) : <div />}
            <div className="flex gap-2">
                <button type="button" onClick={onClose} className="px-4 py-2 text-sm font-medium text-gray-600 hover:bg-gray-100 rounded-lg transition-colors">Cancel</button>
                <button type="submit" className="px-4 py-2 text-sm font-medium text-white bg-blue-600 rounded-lg hover:bg-blue-700 transition-colors shadow-sm">Save</button>
            </div>
        </div>
      </form>
    </Modal>
  );
};

import React, { useState, useEffect, useRef } from 'react';
import { Modal } from './Modal';
import { CalendarEvent, Region, RecurrenceType } from '../types';
import { toDateString, toTimeString } from '../utils/dateUtils';
import { Clock, MapPin, AlignLeft, Type, Calendar as CalendarIcon, Globe, ChevronDown, Repeat, Check } from 'lucide-react';
import { MiniCalendar } from './MiniCalendar';

interface EventModalProps {
  isOpen: boolean;
  onClose: () => void;
  onSave: (event: CalendarEvent) => void;
  onDelete: (id: string) => void;
  initialDate?: Date | null;
  existingEvent?: CalendarEvent | null;
}

interface DateInputProps {
    dateStr: string; // ISO YYYY-MM-DD
    onChange: (iso: string) => void;
    onFocus: () => void;
    inputRef?: React.RefObject<HTMLInputElement | null>; 
    onComplete?: () => void; 
}

const DateInput: React.FC<DateInputProps> = ({ dateStr, onChange, onFocus, inputRef, onComplete }) => {
    const [d, setD] = useState('');
    const [m, setM] = useState('');
    const [y, setY] = useState('');

    const monthRef = useRef<HTMLInputElement>(null);
    const yearRef = useRef<HTMLInputElement>(null);
    const isFocused = useRef(false);

    useEffect(() => {
        if (isFocused.current) return;
        if (dateStr) {
            const [year, month, day] = dateStr.split('-');
            setY(year);
            setM(month);
            setD(day);
        } else {
            setD(''); setM(''); setY('');
        }
    }, [dateStr]);

    const updateDate = (day: string, month: string, year: string) => {
        if (day.length >= 1 && month.length >= 1 && year.length === 4) {
             const newDate = new Date(parseInt(year), parseInt(month) - 1, parseInt(day));
             if (newDate.getDate() === parseInt(day) && newDate.getMonth() === parseInt(month) - 1) {
                 onChange(toDateString(newDate));
             }
        }
    };

    const handleDayChange = (e: React.ChangeEvent<HTMLInputElement>) => {
        let val = e.target.value;
        if (!/^\d*$/.test(val)) return;
        setD(val);
        updateDate(val, m, y);
        if (val.length === 2) monthRef.current?.focus();
    };

    const handleMonthChange = (e: React.ChangeEvent<HTMLInputElement>) => {
        let val = e.target.value;
        if (!/^\d*$/.test(val)) return;
        setM(val);
        updateDate(d, val, y);
        if (val.length === 2) yearRef.current?.focus();
    };

    const handleYearChange = (e: React.ChangeEvent<HTMLInputElement>) => {
        let val = e.target.value;
        if (!/^\d*$/.test(val)) return;
        setY(val);
        updateDate(d, m, val);
        if (val.length === 4 && onComplete) {
            onComplete();
        }
    };

    const handleDayBlur = () => {
        isFocused.current = false;
        if (d === '' && dateStr) {
             const [_, __, day] = dateStr.split('-');
             setD(day);
        }
    };

    const handleMonthBlur = () => {
        isFocused.current = false;
        if (m === '' && dateStr) {
             const [_, month, __] = dateStr.split('-');
             setM(month);
        }
    };

    const handleFocus = (e: React.FocusEvent<HTMLInputElement>) => {
        isFocused.current = true;
        e.target.select();
        onFocus();
    };

    return (
        <div className="flex items-center gap-0.5 w-full h-full">
            <input
                ref={inputRef}
                type="text"
                placeholder="DD"
                value={d}
                maxLength={2}
                onChange={handleDayChange}
                onBlur={handleDayBlur}
                onFocus={handleFocus}
                className="bg-transparent outline-none text-gray-700 font-medium text-center w-8 rounded focus:bg-blue-200 transition-colors p-0 placeholder-gray-400"
            />
            <span className="text-gray-400 select-none">/</span>
            <input
                ref={monthRef}
                type="text"
                placeholder="MM"
                value={m}
                maxLength={2}
                onChange={handleMonthChange}
                onBlur={handleMonthBlur}
                onFocus={handleFocus}
                className="bg-transparent outline-none text-gray-700 font-medium text-center w-8 rounded focus:bg-blue-200 transition-colors p-0 placeholder-gray-400"
            />
            <span className="text-gray-400 select-none">/</span>
            <input
                ref={yearRef}
                type="text"
                placeholder="YYYY"
                maxLength={4}
                value={y}
                onChange={handleYearChange}
                onFocus={handleFocus}
                className="bg-transparent outline-none text-gray-700 font-medium text-center w-12 rounded focus:bg-blue-200 transition-colors p-0 placeholder-gray-400"
            />
        </div>
    );
};

interface TimeSelectProps { 
    value: string; 
    onChange: (val: string) => void; 
    inputRef?: React.RefObject<HTMLInputElement | null>;
    onComplete?: () => void;
    onBlur?: (val: string) => void;
}

const TimeSelect: React.FC<TimeSelectProps> = ({ value, onChange, inputRef, onComplete, onBlur }) => {
    const [h = '', m = ''] = (value || '0:0').split(':');
    const minuteRef = useRef<HTMLInputElement>(null);
    const isFocused = useRef(false);

    // Initialize without forced padding
    const [localH, setLocalH] = useState(h);
    const [localM, setLocalM] = useState(m);

    useEffect(() => {
        // Only update from props if not currently editing (prevents overwriting user input)
        if (isFocused.current) return;
        const [newH = '0', newM = '0'] = (value || '0:0').split(':');
        setLocalH(newH);
        setLocalM(newM);
    }, [value]);

    const updateTime = (newH: string, newM: string) => {
        // Pass the raw values; parent or submit handler handles final formatting
        onChange(`${newH}:${newM}`);
    };

    const handleHourChange = (e: React.ChangeEvent<HTMLInputElement>) => {
        let val = e.target.value;
        if (!/^\d*$/.test(val)) return;
        setLocalH(val);
        updateTime(val, localM);
        if (val.length === 2) minuteRef.current?.focus();
    };

    const handleHourBlur = () => {
        isFocused.current = false;
        let val = parseInt(localH, 10);
        if (isNaN(val)) val = 0;

        val = Math.min(23, Math.max(0, val));

        // Pad with 0 if length < 2
        const formatted = val.toString().padStart(2, '0');

        setLocalH(formatted);
        const newVal = `${formatted}:${localM}`;
        updateTime(formatted, localM);
        if (onBlur) onBlur(newVal);
    };

    const handleMinuteChange = (e: React.ChangeEvent<HTMLInputElement>) => {
        let val = e.target.value;
        if (!/^\d*$/.test(val)) return;
        setLocalM(val);
        updateTime(localH, val);
        if (val.length === 2 && onComplete) {
            onComplete();
        }
    };

    const handleMinuteBlur = () => {
        isFocused.current = false;
        let val = parseInt(localM, 10);
        if (isNaN(val)) val = 0;

        val = Math.min(59, Math.max(0, val));

        // Pad with 0 if length < 2
        const formatted = val.toString().padStart(2, '0');

        setLocalM(formatted);
        const newVal = `${localH}:${formatted}`;
        updateTime(localH, formatted);
        if (onBlur) onBlur(newVal);
    };

    const handleFocus = (e: React.FocusEvent<HTMLInputElement>) => {
        isFocused.current = true;
        e.target.select();
    };

    return (
        <div className="flex items-center border border-gray-200 rounded-lg bg-gray-50 h-10 w-32 relative transition-all hover:border-gray-300 group">
             <div className="absolute inset-y-0 left-0 pl-2 flex items-center pointer-events-none text-gray-400 z-10">
                <Clock size={16} />
            </div>
            <div className="flex items-center pl-8 pr-2 w-full justify-between">
                <input 
                    ref={inputRef}
                    type="text"
                    value={localH} 
                    maxLength={2}
                    onChange={handleHourChange}
                    onBlur={handleHourBlur}
                    onFocus={handleFocus}
                    placeholder="HH"
                    className="bg-transparent outline-none text-gray-700 font-medium text-center w-9 rounded focus:bg-blue-200 transition-colors p-0"
                />
                <span className="text-gray-400 font-medium select-none">:</span>
                <input 
                    ref={minuteRef}
                    type="text"
                    value={localM} 
                    maxLength={2}
                    onChange={handleMinuteChange}
                    onBlur={handleMinuteBlur}
                    onFocus={handleFocus}
                    placeholder="MM"
                    className="bg-transparent outline-none text-gray-700 font-medium text-center w-9 rounded focus:bg-blue-200 transition-colors p-0"
                />
            </div>
        </div>
    );
};

export const EventModal: React.FC<EventModalProps> = ({ 
  isOpen, 
  onClose, 
  onSave, 
  onDelete,
  initialDate, 
  existingEvent 
}) => {
  const [title, setTitle] = useState('');
  const [startDate, setStartDate] = useState(''); 
  const [startTime, setStartTime] = useState('');
  const [endDate, setEndDate] = useState(''); 
  const [endTime, setEndTime] = useState('');
  const [description, setDescription] = useState('');
  const [location, setLocation] = useState('');
  const [region, setRegion] = useState<Region>(Region.IWAMI);
  const [isAllDay, setIsAllDay] = useState(false);
  const [recurrence, setRecurrence] = useState<RecurrenceType>('none');

  const [activeDateField, setActiveDateField] = useState<'start' | 'end' | null>(null);
  const [calendarPos, setCalendarPos] = useState<'top' | 'bottom'>('bottom');

  const startDateRef = useRef<HTMLDivElement>(null);
  const endDateRef = useRef<HTMLDivElement>(null);
  const startHourRef = useRef<HTMLInputElement>(null);
  const endDayInputRef = useRef<HTMLInputElement>(null);
  const endHourRef = useRef<HTMLInputElement>(null);

  useEffect(() => {
    if (isOpen) {
      if (existingEvent) {
        setTitle(existingEvent.title);
        const s = new Date(existingEvent.start);
        const e = new Date(existingEvent.end);
        setStartDate(toDateString(s));
        setStartTime(toTimeString(s));
        setEndDate(toDateString(e));
        setEndTime(toTimeString(e));
        setDescription(existingEvent.description || '');
        setLocation(existingEvent.location || '');
        setRegion(existingEvent.region || Region.IWAMI);
        setIsAllDay(existingEvent.isAllDay);
        setRecurrence(existingEvent.recurrence || 'none');
      } else {
        if (initialDate) {
             const s = new Date(initialDate);
             s.setHours(9, 0, 0, 0); 
             const e = new Date(s);
             e.setHours(10, 0, 0, 0); 
             setStartDate(toDateString(s));
             setStartTime(toTimeString(s));
             setEndDate(toDateString(e));
             setEndTime(toTimeString(e));
        } else {
             setStartDate('');
             setStartTime('');
             setEndDate('');
             setEndTime('');
        }
        setTitle('');
        setDescription('');
        setLocation('');
        setRegion(Region.IWAMI);
        setIsAllDay(false);
        setRecurrence('none');
      }
      setActiveDateField(null);
    }
  }, [isOpen, existingEvent, initialDate]);

  useEffect(() => {
    const handleClickOutside = (event: MouseEvent) => {
        if (activeDateField === 'start' && startDateRef.current && !startDateRef.current.contains(event.target as Node)) {
            setActiveDateField(null);
        } else if (activeDateField === 'end' && endDateRef.current && !endDateRef.current.contains(event.target as Node)) {
            setActiveDateField(null);
        }
    };
    if (activeDateField) {
        document.addEventListener('mousedown', handleClickOutside);
    }
    return () => {
        document.removeEventListener('mousedown', handleClickOutside);
    };
  }, [activeDateField]);

  // Helper to ensure proper time formatting
  const padTime = (timeStr: string) => {
      const parts = (timeStr || '0:0').split(':');
      const h = parts[0] || '0';
      const m = parts[1] || '0';
      return `${h.padStart(2, '0')}:${m.padStart(2, '0')}`;
  };

  const handleStartTimeBlur = (currentStartTime: string) => {
    if (!startDate || !endDate) return;

    const sTime = padTime(currentStartTime);
    const eTime = padTime(endTime);

    const startIso = `${startDate}T${sTime}:00`;
    const endIso = `${endDate}T${eTime}:00`;

    const startObj = new Date(startIso);
    const endObj = new Date(endIso);

    if (!isNaN(startObj.getTime()) && !isNaN(endObj.getTime())) {
        if (endObj < startObj) {
            // Set end to start + 1 hour
            const newEnd = new Date(startObj.getTime() + 60 * 60 * 1000);
            setEndDate(toDateString(newEnd));
            setEndTime(toTimeString(newEnd));
        }
    }
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!startDate || !endDate) return; 

    const sTime = isAllDay ? '00:00' : padTime(startTime || '00:00');
    const eTime = isAllDay ? '00:00' : padTime(endTime || '00:00');

    const startIso = `${startDate}T${sTime}:00`;
    const endIso = `${endDate}T${eTime}:00`;

    const startDateObj = new Date(startIso);
    const endDateObj = new Date(endIso);

    if (endDateObj < startDateObj) {
        alert("End time cannot be before start time.");
        return;
    }

    onSave({
      id: existingEvent?.id || crypto.randomUUID(),
      title,
      start: startIso,
      end: endIso,
      description,
      location,
      region,
      isAllDay,
      recurrence
    });
    onClose();
  };

  const handleDateSelect = (field: 'start' | 'end', newDate: Date) => {
    const dateStr = toDateString(newDate);
    if (field === 'start') {
        setStartDate(dateStr);
        if (!endDate || new Date(dateStr) > new Date(endDate)) {
            setEndDate(dateStr);
        }
    } else {
        setEndDate(dateStr);
    }
    setActiveDateField(null);
  };

  const openCalendar = (field: 'start' | 'end') => {
    const ref = field === 'start' ? startDateRef : endDateRef;
    if (ref.current) {
        const rect = ref.current.getBoundingClientRect();
        const spaceBelow = window.innerHeight - rect.bottom;
        setCalendarPos(spaceBelow < 320 ? 'top' : 'bottom');
    }
    setActiveDateField(field);
  };

  return (
    <Modal 
        isOpen={isOpen} 
        onClose={onClose} 
        title={existingEvent ? 'Edit Event' : 'New Event'}
    >
      <form onSubmit={handleSubmit} className="space-y-4 relative">
        <div className="space-y-1">
            <label className="text-xs font-semibold text-gray-500 uppercase tracking-wider">Event Title</label>
            <div className="relative">
                <div className="absolute inset-y-0 left-0 pl-3 flex items-center pointer-events-none text-gray-400">
                    <Type size={16} />
                </div>
                <input
                    type="text"
                    required
                    value={title}
                    onChange={(e) => setTitle(e.target.value)}
                    placeholder="Add title"
                    className="w-full pl-10 pr-3 py-2 text-gray-700 bg-gray-50 border border-gray-200 rounded-lg focus:ring-2 focus:ring-blue-500 focus:border-transparent outline-none transition-all"
                />
            </div>
        </div>

        <div className="grid grid-cols-1 gap-3">
             <div className="space-y-1">
                <label className="text-xs font-semibold text-gray-500 uppercase tracking-wider">Start</label>
                <div className="flex gap-2">
                     <div 
                        className="relative group flex-grow flex items-center bg-gray-50 border border-gray-200 rounded-lg h-10 pl-10 focus-within:ring-2 focus-within:ring-blue-500 transition-all hover:border-gray-300" 
                        ref={startDateRef}
                     >
                        <div className="absolute inset-y-0 left-0 pl-3 flex items-center pointer-events-none text-gray-400 z-10">
                            <CalendarIcon size={16} />
                        </div>
                        <DateInput 
                            dateStr={startDate}
                            onChange={(iso) => {
                                setStartDate(iso);
                                if (!endDate || new Date(iso) > new Date(endDate)) setEndDate(iso);
                            }}
                            onFocus={() => openCalendar('start')}
                            onComplete={() => isAllDay ? endDayInputRef.current?.focus() : startHourRef.current?.focus()}
                        />
                         {activeDateField === 'start' && (
                            <div className={`absolute left-0 z-50 ${calendarPos === 'top' ? 'bottom-full mb-2' : 'top-full mt-2'}`}>
                                 <MiniCalendar 
                                    initialDate={startDate ? new Date(startDate) : new Date()} 
                                    onSelectDate={(d) => handleDateSelect('start', d)} 
                                    onClose={() => setActiveDateField(null)} 
                                />
                            </div>
                        )}
                     </div>
                     {!isAllDay && (
                        <TimeSelect 
                            value={startTime} 
                            onChange={setStartTime} 
                            inputRef={startHourRef}
                            onComplete={() => endDayInputRef.current?.focus()}
                            onBlur={handleStartTimeBlur}
                        />
                     )}
                </div>
            </div>

            <div className="space-y-1">
                <label className="text-xs font-semibold text-gray-500 uppercase tracking-wider">End</label>
                <div className="flex gap-2">
                     <div 
                        className="relative group flex-grow flex items-center bg-gray-50 border border-gray-200 rounded-lg h-10 pl-10 focus-within:ring-2 focus-within:ring-blue-500 transition-all hover:border-gray-300" 
                        ref={endDateRef}
                    >
                        <div className="absolute inset-y-0 left-0 pl-3 flex items-center pointer-events-none text-gray-400 z-10">
                            <CalendarIcon size={16} />
                        </div>
                         <DateInput 
                            dateStr={endDate}
                            onChange={setEndDate}
                            onFocus={() => openCalendar('end')}
                            inputRef={endDayInputRef}
                            onComplete={() => !isAllDay && endHourRef.current?.focus()}
                        />
                        {activeDateField === 'end' && (
                            <div className={`absolute left-0 z-50 ${calendarPos === 'top' ? 'bottom-full mb-2' : 'top-full mt-2'}`}>
                                <MiniCalendar 
                                    initialDate={endDate ? new Date(endDate) : new Date()} 
                                    onSelectDate={(d) => handleDateSelect('end', d)} 
                                    onClose={() => setActiveDateField(null)} 
                                />
                            </div>
                        )}
                    </div>
                    {!isAllDay && (
                         <TimeSelect 
                            value={endTime} 
                            onChange={setEndTime}
                            inputRef={endHourRef} 
                         />
                    )}
                </div>
            </div>
        </div>

        <div className="flex flex-wrap items-center gap-6">
            <div className="flex items-center gap-2">
                <label htmlFor="isAllDay" className="relative flex items-center gap-2 cursor-pointer group">
                    <input 
                        type="checkbox" 
                        id="isAllDay"
                        checked={isAllDay}
                        onChange={(e) => setIsAllDay(e.target.checked)}
                        className="sr-only"
                    />
                    <div className={`
                        w-5 h-5 flex items-center justify-center rounded border-2 transition-all
                        ${isAllDay ? 'bg-white border-gray-900' : 'bg-white border-gray-300 group-hover:border-gray-400'}
                    `}>
                        {isAllDay && <Check size={14} className="text-black stroke-[3.5px]" />}
                    </div>
                    <span className="text-sm text-gray-700 font-medium select-none">All day</span>
                </label>
            </div>

            <div className="flex items-center gap-2">
                <div className="text-gray-400">
                    <Repeat size={16} />
                </div>
                <select
                    value={recurrence}
                    onChange={(e) => setRecurrence(e.target.value as RecurrenceType)}
                    className="bg-transparent border-none text-sm text-gray-700 font-medium focus:ring-0 cursor-pointer outline-none"
                >
                    <option value="none">No repeat</option>
                    <option value="monthly">Monthly</option>
                    <option value="yearly">Yearly</option>
                </select>
            </div>
        </div>

        <div className="space-y-1">
            <label className="text-xs font-semibold text-gray-500 uppercase tracking-wider">Location</label>
            <div className="relative">
                <div className="absolute inset-y-0 left-0 pl-3 flex items-center pointer-events-none text-gray-400">
                    <MapPin size={16} />
                </div>
                <input
                    type="text"
                    value={location}
                    onChange={(e) => setLocation(e.target.value)}
                    placeholder="Add location"
                    className="w-full pl-10 pr-3 py-2 text-gray-700 bg-gray-50 border border-gray-200 rounded-lg focus:ring-2 focus:ring-blue-500 outline-none"
                />
            </div>
        </div>

        <div className="space-y-1">
            <label className="text-xs font-semibold text-gray-500 uppercase tracking-wider">Description</label>
            <div className="relative">
                 <div className="absolute top-3 left-3 flex items-start pointer-events-none text-gray-400">
                    <AlignLeft size={16} />
                </div>
                <textarea
                    value={description}
                    onChange={(e) => setDescription(e.target.value)}
                    placeholder="Add description"
                    className="w-full pl-10 pr-3 py-2 text-gray-700 bg-gray-50 border border-gray-200 rounded-lg focus:ring-2 focus:ring-blue-500 outline-none resize-none h-20"
                />
            </div>
        </div>

        <div className="space-y-1">
            <label className="text-xs font-semibold text-gray-500 uppercase tracking-wider">Region</label>
            <div className="relative">
                <div className="absolute inset-y-0 left-0 pl-3 flex items-center pointer-events-none text-gray-400">
                    <Globe size={16} />
                </div>
                <select
                    value={region}
                    onChange={(e) => setRegion(e.target.value as Region)}
                    className="w-full pl-10 pr-8 py-2 text-gray-700 bg-gray-50 border border-gray-200 rounded-lg focus:ring-2 focus:ring-blue-500 focus:border-transparent outline-none appearance-none transition-all cursor-pointer"
                >
                    {Object.values(Region).map((r) => (
                        <option key={r} value={r}>{r}</option>
                    ))}
                </select>
                 <div className="absolute inset-y-0 right-0 pr-3 flex items-center pointer-events-none text-gray-400">
                    <ChevronDown size={16} />
                 </div>
            </div>
        </div>

        <div className="flex justify-between pt-4 border-t border-gray-100 mt-2">
            {existingEvent ? (
                 <button
                 type="button"
                 onClick={() => {
                     onDelete(existingEvent.id);
                     onClose();
                 }}
                 className="px-4 py-2 text-sm font-medium text-red-600 hover:bg-red-50 rounded-lg transition-colors"
             >
                 Delete
             </button>
            ) : <div />}
            <div className="flex gap-2">
                <button type="button" onClick={onClose} className="px-4 py-2 text-sm font-medium text-gray-600 hover:bg-gray-100 rounded-lg transition-colors">Cancel</button>
                <button type="submit" className="px-4 py-2 text-sm font-medium text-white bg-blue-600 rounded-lg hover:bg-blue-700 transition-colors shadow-sm">Save</button>
            </div>
        </div>
      </form>
    </Modal>
  );
};

import React, { useState, useEffect, useRef } from 'react';
import { Modal } from './Modal';
import { CalendarEvent, Region, RecurrenceType } from '../types';
import { toDateString, toTimeString } from '../utils/dateUtils';
import { Clock, MapPin, AlignLeft, Type, Calendar as CalendarIcon, Globe, ChevronDown, Repeat, Check, AlertCircle } from 'lucide-react';
import { MiniCalendar } from './MiniCalendar';

interface EventModalProps {
  isOpen: boolean;
  onClose: () => void;
  onSave: (event: CalendarEvent) => void;
  onDelete: (id: string) => void;
  initialDate?: Date | null;
  existingEvent?: CalendarEvent | null;
}

interface DateInputProps {
    dateStr: string; // ISO YYYY-MM-DD
    onChange: (iso: string) => void;
    onFocus: () => void;
    inputRef?: React.RefObject<HTMLInputElement | null>; 
    onComplete?: () => void; 
}

const DateInput: React.FC<DateInputProps> = ({ dateStr, onChange, onFocus, inputRef, onComplete }) => {
    const [d, setD] = useState('');
    const [m, setM] = useState('');
    const [y, setY] = useState('');

    const monthRef = useRef<HTMLInputElement>(null);
    const yearRef = useRef<HTMLInputElement>(null);
    const isFocused = useRef(false);

    useEffect(() => {
        if (isFocused.current) return;
        if (dateStr) {
            const [year, month, day] = dateStr.split('-');
            setY(year);
            setM(month);
            setD(day);
        } else {
            setD(''); setM(''); setY('');
        }
    }, [dateStr]);

    const updateDate = (day: string, month: string, year: string) => {
        if (day.length >= 1 && month.length >= 1 && year.length === 4) {
             const newDate = new Date(parseInt(year), parseInt(month) - 1, parseInt(day));
             if (newDate.getDate() === parseInt(day) && newDate.getMonth() === parseInt(month) - 1) {
                 onChange(toDateString(newDate));
             }
        }
    };

    const handleDayChange = (e: React.ChangeEvent<HTMLInputElement>) => {
        let val = e.target.value;
        if (!/^\d*$/.test(val)) return;
        setD(val);
        updateDate(val, m, y);
        if (val.length === 2) monthRef.current?.focus();
    };

    const handleMonthChange = (e: React.ChangeEvent<HTMLInputElement>) => {
        let val = e.target.value;
        if (!/^\d*$/.test(val)) return;
        setM(val);
        updateDate(d, val, y);
        if (val.length === 2) yearRef.current?.focus();
    };

    const handleYearChange = (e: React.ChangeEvent<HTMLInputElement>) => {
        let val = e.target.value;
        if (!/^\d*$/.test(val)) return;
        setY(val);
        updateDate(d, m, val);
        if (val.length === 4 && onComplete) {
            onComplete();
        }
    };

    const handleDayBlur = () => {
        isFocused.current = false;
        if (d === '' && dateStr) {
             const [_, __, day] = dateStr.split('-');
             setD(day);
        }
    };

    const handleMonthBlur = () => {
        isFocused.current = false;
        if (m === '' && dateStr) {
             const [_, month, __] = dateStr.split('-');
             setM(month);
        }
    };

    const handleFocus = (e: React.FocusEvent<HTMLInputElement>) => {
        isFocused.current = true;
        e.target.select();
        onFocus();
    };

    return (
        <div className="flex items-center gap-0.5 w-full h-full">
            <input
                ref={inputRef}
                type="text"
                placeholder="DD"
                value={d}
                maxLength={2}
                onChange={handleDayChange}
                onBlur={handleDayBlur}
                onFocus={handleFocus}
                className="bg-transparent outline-none text-gray-700 font-medium text-center w-8 rounded focus:bg-blue-200 transition-colors p-0 placeholder-gray-400"
            />
            <span className="text-gray-400 select-none">/</span>
            <input
                ref={monthRef}
                type="text"
                placeholder="MM"
                value={m}
                maxLength={2}
                onChange={handleMonthChange}
                onBlur={handleMonthBlur}
                onFocus={handleFocus}
                className="bg-transparent outline-none text-gray-700 font-medium text-center w-8 rounded focus:bg-blue-200 transition-colors p-0 placeholder-gray-400"
            />
            <span className="text-gray-400 select-none">/</span>
            <input
                ref={yearRef}
                type="text"
                placeholder="YYYY"
                maxLength={4}
                value={y}
                onChange={handleYearChange}
                onFocus={handleFocus}
                className="bg-transparent outline-none text-gray-700 font-medium text-center w-12 rounded focus:bg-blue-200 transition-colors p-0 placeholder-gray-400"
            />
        </div>
    );
};

interface TimeSelectProps { 
    value: string; 
    onChange: (val: string) => void; 
    inputRef?: React.RefObject<HTMLInputElement | null>;
    onComplete?: () => void;
    onBlur?: (val: string) => void;
    hasError?: boolean;
}

const TimeSelect: React.FC<TimeSelectProps> = ({ value, onChange, inputRef, onComplete, onBlur, hasError }) => {
    const [h = '', m = ''] = (value || '0:0').split(':');
    const minuteRef = useRef<HTMLInputElement>(null);
    const isFocused = useRef(false);

    // Initialize without forced padding
    const [localH, setLocalH] = useState(h);
    const [localM, setLocalM] = useState(m);

    useEffect(() => {
        // Only update from props if not currently editing (prevents overwriting user input)
        if (isFocused.current) return;
        const [newH = '0', newM = '0'] = (value || '0:0').split(':');
        setLocalH(newH);
        setLocalM(newM);
    }, [value]);

    const updateTime = (newH: string, newM: string) => {
        // Pass the raw values; parent or submit handler handles final formatting
        onChange(`${newH}:${newM}`);
    };

    const handleHourChange = (e: React.ChangeEvent<HTMLInputElement>) => {
        let val = e.target.value;
        if (!/^\d*$/.test(val)) return;
        setLocalH(val);
        updateTime(val, localM);
        if (val.length === 2) minuteRef.current?.focus();
    };

    const handleHourBlur = () => {
        isFocused.current = false;
        let val = parseInt(localH, 10);
        if (isNaN(val)) val = 0;

        val = Math.min(23, Math.max(0, val));

        // Pad with 0 if length < 2
        const formatted = val.toString().padStart(2, '0');

        setLocalH(formatted);
        const newVal = `${formatted}:${localM}`;
        updateTime(formatted, localM);
        if (onBlur) onBlur(newVal);
    };

    const handleMinuteChange = (e: React.ChangeEvent<HTMLInputElement>) => {
        let val = e.target.value;
        if (!/^\d*$/.test(val)) return;
        setLocalM(val);
        updateTime(localH, val);
        if (val.length === 2 && onComplete) {
            onComplete();
        }
    };

    const handleMinuteBlur = () => {
        isFocused.current = false;
        let val = parseInt(localM, 10);
        if (isNaN(val)) val = 0;

        val = Math.min(59, Math.max(0, val));

        // Pad with 0 if length < 2
        const formatted = val.toString().padStart(2, '0');

        setLocalM(formatted);
        const newVal = `${localH}:${formatted}`;
        updateTime(localH, formatted);
        if (onBlur) onBlur(newVal);
    };

    const handleFocus = (e: React.FocusEvent<HTMLInputElement>) => {
        isFocused.current = true;
        e.target.select();
    };

    return (
        <div className={`flex items-center border rounded-lg h-10 w-32 relative transition-all group ${hasError ? 'border-red-300 bg-red-50' : 'border-gray-200 bg-gray-50 hover:border-gray-300'}`}>
             <div className={`absolute inset-y-0 left-0 pl-2 flex items-center pointer-events-none z-10 ${hasError ? 'text-red-400' : 'text-gray-400'}`}>
                <Clock size={16} />
            </div>
            <div className="flex items-center pl-8 pr-2 w-full justify-between">
                <input 
                    ref={inputRef}
                    type="text"
                    value={localH} 
                    maxLength={2}
                    onChange={handleHourChange}
                    onBlur={handleHourBlur}
                    onFocus={handleFocus}
                    placeholder="HH"
                    className={`bg-transparent outline-none font-medium text-center w-9 rounded transition-colors p-0 ${hasError ? 'text-red-700 focus:bg-red-100' : 'text-gray-700 focus:bg-blue-200'}`}
                />
                <span className={`font-medium select-none ${hasError ? 'text-red-400' : 'text-gray-400'}`}>:</span>
                <input 
                    ref={minuteRef}
                    type="text"
                    value={localM} 
                    maxLength={2}
                    onChange={handleMinuteChange}
                    onBlur={handleMinuteBlur}
                    onFocus={handleFocus}
                    placeholder="MM"
                    className={`bg-transparent outline-none font-medium text-center w-9 rounded transition-colors p-0 ${hasError ? 'text-red-700 focus:bg-red-100' : 'text-gray-700 focus:bg-blue-200'}`}
                />
            </div>
        </div>
    );
};

export const EventModal: React.FC<EventModalProps> = ({ 
  isOpen, 
  onClose, 
  onSave, 
  onDelete,
  initialDate, 
  existingEvent 
}) => {
  const [title, setTitle] = useState('');
  const [startDate, setStartDate] = useState(''); 
  const [startTime, setStartTime] = useState('');
  const [endDate, setEndDate] = useState(''); 
  const [endTime, setEndTime] = useState('');
  const [description, setDescription] = useState('');
  const [location, setLocation] = useState('');
  const [region, setRegion] = useState<Region>(Region.IWAMI);
  const [isAllDay, setIsAllDay] = useState(false);
  const [recurrence, setRecurrence] = useState<RecurrenceType>('none');

  const [timeError, setTimeError] = useState<string | null>(null);

  const [activeDateField, setActiveDateField] = useState<'start' | 'end' | null>(null);
  const [calendarPos, setCalendarPos] = useState<'top' | 'bottom'>('bottom');

  const startDateRef = useRef<HTMLDivElement>(null);
  const endDateRef = useRef<HTMLDivElement>(null);
  const startHourRef = useRef<HTMLInputElement>(null);
  const endDayInputRef = useRef<HTMLInputElement>(null);
  const endHourRef = useRef<HTMLInputElement>(null);

  useEffect(() => {
    if (isOpen) {
      if (existingEvent) {
        setTitle(existingEvent.title);
        const s = new Date(existingEvent.start);
        const e = new Date(existingEvent.end);
        setStartDate(toDateString(s));
        setStartTime(toTimeString(s));
        setEndDate(toDateString(e));
        setEndTime(toTimeString(e));
        setDescription(existingEvent.description || '');
        setLocation(existingEvent.location || '');
        setRegion(existingEvent.region || Region.IWAMI);
        setIsAllDay(existingEvent.isAllDay);
        setRecurrence(existingEvent.recurrence || 'none');
      } else {
        if (initialDate) {
             const s = new Date(initialDate);
             s.setHours(9, 0, 0, 0); 
             const e = new Date(s);
             e.setHours(10, 0, 0, 0); 
             setStartDate(toDateString(s));
             setStartTime(toTimeString(s));
             setEndDate(toDateString(e));
             setEndTime(toTimeString(e));
        } else {
             setStartDate('');
             setStartTime('');
             setEndDate('');
             setEndTime('');
        }
        setTitle('');
        setDescription('');
        setLocation('');
        setRegion(Region.IWAMI);
        setIsAllDay(false);
        setRecurrence('none');
      }
      setActiveDateField(null);
      setTimeError(null);
    }
  }, [isOpen, existingEvent, initialDate]);

  useEffect(() => {
    const handleClickOutside = (event: MouseEvent) => {
        if (activeDateField === 'start' && startDateRef.current && !startDateRef.current.contains(event.target as Node)) {
            setActiveDateField(null);
        } else if (activeDateField === 'end' && endDateRef.current && !endDateRef.current.contains(event.target as Node)) {
            setActiveDateField(null);
        }
    };
    if (activeDateField) {
        document.addEventListener('mousedown', handleClickOutside);
    }
    return () => {
        document.removeEventListener('mousedown', handleClickOutside);
    };
  }, [activeDateField]);

  // Validation Effect for Same Day Time Constraint
  useEffect(() => {
    if (isAllDay) {
        setTimeError(null);
        return;
    }

    if (startDate && endDate && startDate === endDate) {
        const [sh, sm] = (startTime || '0:0').split(':').map(Number);
        const [eh, em] = (endTime || '0:0').split(':').map(Number);

        const startTotal = (sh || 0) * 60 + (sm || 0);
        const endTotal = (eh || 0) * 60 + (em || 0);

        if (endTotal < startTotal) {
            setTimeError("End time must be after start time");
        } else {
            setTimeError(null);
        }
    } else {
        setTimeError(null);
    }
  }, [startDate, endDate, startTime, endTime, isAllDay]);

  // Helper to ensure proper time formatting
  const padTime = (timeStr: string) => {
      const parts = (timeStr || '0:0').split(':');
      const h = parts[0] || '0';
      const m = parts[1] || '0';
      return `${h.padStart(2, '0')}:${m.padStart(2, '0')}`;
  };

  const handleStartTimeBlur = (currentStartTime: string) => {
    if (!startDate || !endDate) return;

    const sTime = padTime(currentStartTime);
    const eTime = padTime(endTime);

    const startIso = `${startDate}T${sTime}:00`;
    const endIso = `${endDate}T${eTime}:00`;

    const startObj = new Date(startIso);
    const endObj = new Date(endIso);

    if (!isNaN(startObj.getTime()) && !isNaN(endObj.getTime())) {
        if (endObj < startObj) {
            // Set end to start + 1 hour
            const newEnd = new Date(startObj.getTime() + 60 * 60 * 1000);
            setEndDate(toDateString(newEnd));
            setEndTime(toTimeString(newEnd));
        }
    }
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!startDate || !endDate) return; 

    if (timeError) {
        // Prevent submission if there's a specific time error
        // Optionally focus the end time field or shake form
        return;
    }

    const sTime = isAllDay ? '00:00' : padTime(startTime || '00:00');
    const eTime = isAllDay ? '00:00' : padTime(endTime || '00:00');

    const startIso = `${startDate}T${sTime}:00`;
    const endIso = `${endDate}T${eTime}:00`;

    const startDateObj = new Date(startIso);
    const endDateObj = new Date(endIso);

    if (endDateObj < startDateObj) {
        alert("End time cannot be before start time.");
        return;
    }

    onSave({
      id: existingEvent?.id || crypto.randomUUID(),
      title,
      start: startIso,
      end: endIso,
      description,
      location,
      region,
      isAllDay,
      recurrence
    });
    onClose();
  };

  const handleDateSelect = (field: 'start' | 'end', newDate: Date) => {
    const dateStr = toDateString(newDate);
    if (field === 'start') {
        setStartDate(dateStr);
        if (!endDate || new Date(dateStr) > new Date(endDate)) {
            setEndDate(dateStr);
        }
    } else {
        setEndDate(dateStr);
    }
    setActiveDateField(null);
  };

  const openCalendar = (field: 'start' | 'end') => {
    const ref = field === 'start' ? startDateRef : endDateRef;
    if (ref.current) {
        const rect = ref.current.getBoundingClientRect();
        const spaceBelow = window.innerHeight - rect.bottom;
        setCalendarPos(spaceBelow < 320 ? 'top' : 'bottom');
    }
    setActiveDateField(field);
  };

