// components/EventModal.tsx
import React, { useState, useEffect, useRef } from 'react';
import { TimeSelect } from './TimeSelect';

interface EventModalProps {
    // ... other props
    startTime: string; // "HH:MM" format
    onStartTimeChange: (newTime: string) => void;
    // ... other props
}

export const EventModal: React.FC<EventModalProps> = ({
    startTime,
    onStartTimeChange,
    // ... other props
}) => {
    const [localStartTime, setLocalStartTime] = useState(startTime);
    const [isTimeSelectOpen, setIsTimeSelectOpen] = useState(false);
    const timeSelectRef = useRef<HTMLDivElement>(null);

    const handleStartTimeBlur = () => {
        setIsTimeSelectOpen(false);
        // Ensure localStartTime is formatted before continuing
        const currentStartTime = localStartTime; // Correct time string "HH:MM"
        const [hour, minute] = currentStartTime.split(':').map(Number);

        // Ensure valid time data
        if(isNaN(hour) || isNaN(minute)) return;

        // No end time adjustment if not the same date
        if (endDateObj) {
            const startDate = new Date(startDateObj);
            const endDate = new Date(endDateObj);
            if (startDate.toDateString() !== endDate.toDateString()) {
                return;
            }
        }

        const startTimeObj = new Date(startDateObj);
        startTimeObj.setHours(hour, minute, 0, 0);

        // This Date object should compare against, not use
        const adjustedEndTime = new Date(startTimeObj); // Start Date
        if (!endDateObj) return;

        // If the start date is invalid, just return
        if(isNaN(startTimeObj.getTime())) return;

        const endTime = new Date(endDateObj);

        // Convert to milliseconds for comparison
        const startTimeMilliseconds = startTimeObj.getTime();
        const endTimeMilliseconds = endTime.getTime();

        if (startTimeMilliseconds > endTimeMilliseconds) {
            // Adjust the end time
            endTime.setHours(hour, minute, 0, 0);
            const endTimeStr = padTime(endTime.getHours().toString()) + ':' + padTime(endTime.getMinutes().toString());
            onEndTimeChange(endTimeStr);
        }
    };

    const handleLocalStartTimeChange = (newTime: string) => {
        setLocalStartTime(newTime);
        onStartTimeChange(newTime);
    };

    const padTime = (timeStr: string) => {
        const parts = (timeStr || '0:0').split(':');
        const h = parts[0] || '0';
        const m = parts[1] || '0';
        const paddedH = h.padStart(2, '0');
        const paddedM = m.padStart(2, '0');
        return `${paddedH}:${paddedM}`;
    };

    useEffect(() => {
        setLocalStartTime(startTime);
    }, [startTime]);

    return (
        <div>
            <TimeSelect
                value={localStartTime}
                onBlur={handleStartTimeBlur}
                onChange={handleLocalStartTimeChange}
                ref={timeSelectRef}
            />
        </div>
    );
};
```
